const downloadBlob = (blob, filename) => {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
};
const docxRuns = (text = '', opts = {}) => {
  const chunks = String(text).split(/(\*\*[^*]+\*\*)/g).filter(Boolean);
  return chunks.map(chunk => {
    const bold = opts.bold || (/^\*\*[^*]+\*\*$/.test(chunk));
    const clean = chunk.replace(/^\*\*|\*\*$/g, '');
    const props = [
      bold ? '<w:b/>' : '',
      opts.color ? `<w:color w:val="${opts.color}"/>` : '',
      opts.size ? `<w:sz w:val="${opts.size}"/>` : '',
      opts.italic ? '<w:i/>' : '',
    ].join('');
    return `<w:r>${props ? `<w:rPr>${props}</w:rPr>` : ''}<w:t xml:space="preserve">${escapeXml(clean)}</w:t></w:r>`;
  }).join('');
};
const docxParagraph = (text = '', opts = {}) => {
  const lines = String(text || '').split(/\n+/).filter(line => line.trim());
  if (!lines.length && !opts.pageBreakBefore) return '';
  return lines.map((line, idx) => {
    const pPr = [
      opts.pageBreakBefore && idx === 0 ? '<w:pageBreakBefore/>' : '',
      opts.heading ? `<w:outlineLvl w:val="${opts.heading - 1}"/>` : '',
      opts.center ? '<w:jc w:val="center"/>' : '',
      `<w:spacing w:after="${opts.after ?? 120}" w:line="276" w:lineRule="auto"/>`,
      opts.border ? '<w:pBdr><w:bottom w:val="single" w:sz="8" w:space="4" w:color="E5E7EB"/></w:pBdr>' : '',
    ].join('');
    return `<w:p>${pPr ? `<w:pPr>${pPr}</w:pPr>` : ''}${docxRuns(line, opts)}</w:p>`;
  }).join('');
};
const docxBullet = (text = '') =>
  `<w:p><w:pPr><w:ind w:left="720" w:hanging="360"/><w:spacing w:after="60"/></w:pPr><w:r><w:t xml:space="preserve">• ${escapeXml(htmlishToText(text))}</w:t></w:r></w:p>`;
const docxTable = (rows = []) => {
  if (!rows.length) return '';
  return `<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="pct"/><w:tblBorders><w:top w:val="single" w:sz="4" w:color="C7C7C7"/><w:left w:val="single" w:sz="4" w:color="C7C7C7"/><w:bottom w:val="single" w:sz="4" w:color="C7C7C7"/><w:right w:val="single" w:sz="4" w:color="C7C7C7"/><w:insideH w:val="single" w:sz="4" w:color="C7C7C7"/><w:insideV w:val="single" w:sz="4" w:color="C7C7C7"/></w:tblBorders></w:tblPr>${rows.map(row => `<w:tr>${row.map(cell => `<w:tc><w:tcPr><w:tcW w:w="2500" w:type="pct"/></w:tcPr>${docxParagraph(cell, { after:60 })}</w:tc>`).join('')}</w:tr>`).join('')}</w:tbl>`;
};
const markdownToDocx = (md = '') => {
  const lines = String(md || '').split('\n');
  let xml = '';
  for (let i = 0; i < lines.length;) {
    const line = lines[i];
    if (/^\s*\|.+\|\s*$/.test(line)) {
      const tableLines = [];
      while (i < lines.length && /^\s*\|.+\|\s*$/.test(lines[i])) tableLines.push(lines[i++]);
      const rows = tableLines
        .filter(l => !/^\s*\|[-:\s|]+\|\s*$/.test(l))
        .map(row => row.replace(/^\s*\|\s*/, '').replace(/\s*\|\s*$/, '').split(/\s*\|\s*/).map(htmlishToText));
      xml += docxTable(rows);
      continue;
    }
    if (/^\s*[-*•]\s/.test(line)) {
      while (i < lines.length && /^\s*[-*•]\s/.test(lines[i])) xml += docxBullet(lines[i++].replace(/^\s*[-*•]\s/, ''));
      continue;
    }
    if (!line.trim()) { i++; continue; }
    xml += docxParagraph(line, { after:80 });
    i++;
  }
  return xml;
};
let crcTable = null;
const makeCrcTable = () => {
  const table = new Uint32Array(256);
  for (let n = 0; n < 256; n++) {
    let c = n;
    for (let k = 0; k < 8; k++) c = (c & 1) ? (0xedb88320 ^ (c >>> 1)) : (c >>> 1);
    table[n] = c >>> 0;
  }
  return table;
};
const crc32 = (bytes) => {
  crcTable = crcTable || makeCrcTable();
  let crc = 0xffffffff;
  for (let i = 0; i < bytes.length; i++) crc = crcTable[(crc ^ bytes[i]) & 0xff] ^ (crc >>> 8);
  return (crc ^ 0xffffffff) >>> 0;
};
const u16 = (n) => [n & 255, (n >>> 8) & 255];
const u32 = (n) => [n & 255, (n >>> 8) & 255, (n >>> 16) & 255, (n >>> 24) & 255];
const createZipBlob = (entries, type) => {
  const enc = new TextEncoder();
  const chunks = [];
  const central = [];
  let offset = 0;
  entries.forEach(entry => {
    const name = enc.encode(entry.name);
    const data = enc.encode(entry.content);
    const crc = crc32(data);
    const local = new Uint8Array([
      ...u32(0x04034b50), ...u16(20), ...u16(0), ...u16(0), ...u16(0), ...u16(0),
      ...u32(crc), ...u32(data.length), ...u32(data.length), ...u16(name.length), ...u16(0),
    ]);
    chunks.push(local, name, data);
    central.push({ name, crc, size:data.length, offset });
    offset += local.length + name.length + data.length;
  });
  const centralStart = offset;
  central.forEach(entry => {
    const head = new Uint8Array([
      ...u32(0x02014b50), ...u16(20), ...u16(20), ...u16(0), ...u16(0), ...u16(0), ...u16(0),
      ...u32(entry.crc), ...u32(entry.size), ...u32(entry.size), ...u16(entry.name.length),
      ...u16(0), ...u16(0), ...u16(0), ...u16(0), ...u32(0), ...u32(entry.offset),
    ]);
    chunks.push(head, entry.name);
    offset += head.length + entry.name.length;
  });
  const centralSize = offset - centralStart;
  chunks.push(new Uint8Array([
    ...u32(0x06054b50), ...u16(0), ...u16(0), ...u16(central.length), ...u16(central.length),
    ...u32(centralSize), ...u32(centralStart), ...u16(0),
  ]));
  return new Blob(chunks, { type });
};
const createDocxBlob = (bodyXml) => {
  const documentXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>${bodyXml}<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="1134" w:bottom="1134" w:left="1134" w:header="708" w:footer="708" w:gutter="0"/></w:sectPr></w:body></w:document>`;
  return createZipBlob([
    { name:'[Content_Types].xml', content:`<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/></Types>` },
    { name:'_rels/.rels', content:`<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>` },
    { name:'word/document.xml', content:documentXml },
  ], 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
};

const parseData = (text, namespace = '') => {
  const norm = text.replace(/\r\n/g,'\n');
  const questionStartRe = /(?=(?:^|\n)[ \t]*(?:(?:\*\*|#{2,4})[ \t]*)?Quest[aã]o(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?\d|(?:^|\n)[ \t]*\d{1,3}[ \t]*[).][ \t])/im;

  // Legacy summary
  let summary = '';
  const sm = norm.match(/(?:^|\n)(?:###|##|\*\*)?\s*Resumo(?: de Consolida[çc][aã]o)?\s*\n([\s\S]*)$/i);
  if (sm?.[1]) summary = sm[1].replace(/\n---.*/g,'').trim();

  const questions = [];
  const blocks = norm.split(questionStartRe)
    .filter(b => b.trim());

  let qCount = 0;

  blocks.forEach((block) => {
    if (!block.trim()) return;
    const hasOptions = /(?:^|\n)[ \t]*[A-Ea-e][ \t]*[).:\-–—][ \t]*\S/.test(block);
    if (!hasOptions) return;

    try {
      const idM = block.match(/(?:\*\*|#{2,4})?[ \t]*Quest[aã]o(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?(\d+(?:\.\d+)*)\]?/i) ||
                  block.match(/(?:^|\n)[ \t]*(\d{1,3})[ \t]*[).]/m);
      const rawId = idM ? idM[1] : `${++qCount}`;
      // ID único: combina namespace (topicId/blockId) com o id da questão
      const id = namespace ? `${namespace}_${rawId}` : rawId;

      const firstOptMatch = block.match(/(?:^|\n)([ \t]*[A-Ea-e][ \t]*[).:\-–—][ \t]*\S)/);
      if (!firstOptMatch) return;
      const firstOptIdx = block.indexOf(firstOptMatch[0]);

      const inlineM = block.match(/(?:^|\n)[ \t]*\d{1,3}[ \t]*[).][ \t]*([^\n]{5,})/m);
      const qHeaderM = block.match(/(?:\*\*|#{2,4})?[ \t]*Quest[aã]o[^\n]*\n/i);
      let stmt = '';
      if (inlineM && inlineM.index <= firstOptIdx) {
        stmt = inlineM[1].trim();
        const contStart = block.indexOf(inlineM[0]) + inlineM[0].length;
        if (contStart < firstOptIdx) stmt += ' ' + block.substring(contStart, firstOptIdx).trim();
      } else if (qHeaderM) {
        stmt = block.substring(qHeaderM.index + qHeaderM[0].length, firstOptIdx).trim();
      } else {
        stmt = block.substring(0, firstOptIdx).trim();
      }
      stmt = stmt.trim();
      if (!stmt || stmt.length < 5) return;

      const ansM =
        block.match(/(?:[Aa]lternativa[ \t]+correta|[Gg]abarito(?:[ \t]+oficial)?|[Rr]esposta(?:[ \t]+correta)?|[Cc]orreta)[ \t]*[:\-–—][ \t]*(?:\*{0,2}[ \t]*)?(?:letra[ \t]*)?\(?([A-Ea-e])\)?/im);

      let correct = null;
      let optionsEnd = block.length;

      if (ansM) {
        correct = ansM[1].toUpperCase();
        optionsEnd = ansM.index;
      } else {
        const stM = block.match(/\n[ \t]*\(?([A-Ea-e])\)?[ \t]*(?:\n|$)/m);
        if (stM && stM.index > firstOptIdx + 10) {
          correct = stM[1].toUpperCase();
          optionsEnd = stM.index;
        }
      }

      const optText = block.substring(firstOptIdx, optionsEnd);
      const options = [];
      const optRe = /(?:^|\n)[ \t]*\(?([A-Ea-e])[ \t]*[).:\-–—][ \t]*([\s\S]*?)(?=(?:\n[ \t]*\(?[A-Ea-e][ \t]*[).:\-–—])|\n[ \t]*$|$)/gim;
      let m;
      while ((m = optRe.exec(optText)) !== null) {
        const letter = m[1].toUpperCase();
        const txt = m[2].replace(/\*\*/g,'').replace(/\n/g,' ').trim();
        if (txt) options.push({ letter, txt });
      }
      if (options.length < 2) return;

      let exp = '';
      const labeledExp = extractLabeledSection(block);
      if (labeledExp.length > 5) {
        exp = labeledExp;
      } else if (ansM) {
        const after = block.substring(ansM.index + ansM[0].length).replace(/^\s*\n/,'').trim();
        if (after.length > 5) exp = after;
      }
      const structuredExp = parseQuestionExplanationParts(exp);
      exp = cleanQuestionExplanation(structuredExp.hasStructured ? (structuredExp.lesson || exp) : exp);

      if (correct) {
        const correctOption = options.find(o => o.letter === correct);
        if (!correctOption) return;
        // Seed usa o id completo (com namespace) para garantir embaralhamento consistente
        const seed = id.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
        const seededShuffle = (arr) => {
          const a = [...arr]; let s = seed;
          for (let i = a.length - 1; i > 0; i--) {
            s = (s * 1664525 + 1013904223) & 0xffffffff;
            const j = Math.abs(s) % (i + 1);
            [a[i], a[j]] = [a[j], a[i]];
          }
          return a;
        };
        // Shuffle distratores only, then insert correct at seed-determined position
        const optionPayloads = options.map(o => ({
          originalLetter:o.letter,
          text:o.txt,
          explanation:structuredExp.alternatives?.[o.letter] || '',
          isCorrect:o.letter === correct,
        }));
        const distractors = optionPayloads.filter(o => !o.isCorrect);
        const shuffledDistractors = seededShuffle(distractors);
        // Position of correct answer: spread across all positions using seed
        const nOpts = options.length;
        const correctPos = Math.abs(seed * 2654435761) % nOpts; // well-distributed hash
        const withCorrect = [...shuffledDistractors];
        withCorrect.splice(correctPos, 0, optionPayloads.find(o => o.isCorrect));
        const final = withCorrect.slice(0, nOpts).map((o, i) => ({ ...o, letter: 'ABCDE'[i] }));
        questions.push({
          id,
          statement: stmt,
          options: final,
          explanation: exp,
          explanationParts: structuredExp.hasStructured ? { lesson:exp, alternatives:structuredExp.alternatives } : null,
        });
      } else {
        const final = options.map((o, i) => ({
          letter: 'ABCDE'[i],
          originalLetter:o.letter,
          text: o.txt,
          isCorrect: false,
          explanation:structuredExp.alternatives?.[o.letter] || '',
        }));
        questions.push({ id, statement: stmt, options: final, explanation: '(Gabarito não fornecido — adicione "Gabarito: X" ao texto para marcar a resposta correta.)' });
      }
    } catch(e) {}
  });

  return { questions, summary };
};

// Parser específico para questões abertas (sem alternativas A/B/C/D)
const parseOpenQuestions = (text, namespace='', isEssay=false) => {
  const norm = text.replace(/\r\n/g,'\n');
  const questions = [];
  let qCount = 0;
  const autoEssay = isEssay === 'auto';

  // Dividir por ## Questão N, ## Questão [1.2.1], N) ou N.
  const blocks = norm.split(/(?=(?:^|\n)[ \t]*(?:(?:\*\*|##)[ \t]*)?Quest[aã]o(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?\d|(?:^|\n)[ \t]*\d{1,3}[ \t]*[).][ \t])/im).filter(b=>b.trim());

  blocks.forEach(block => {
    if (!block.trim()) return;
    try {
      const respMatch = block.match(/Resposta esperada:\s*([\s\S]*?)(?:\nExplica[çc][aã]o:|\nAlternativa correta:|\n---|$)/i);
      if (!respMatch) return;
      const idM = block.match(/(?:\*\*|##)?[ \t]*Quest[aã]o(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?(\d+(?:\.\d+)*)\]?/i) || block.match(/(?:^|\n)[ \t]*(\d{1,3})[ \t]*[).]/m);
      const rawId = idM ? idM[1] : `${++qCount}`;
      const id = namespace ? `${namespace}_${rawId}` : rawId;

      // Extrai enunciado: tudo antes de "Resposta esperada:"
      const stmtEnd = respMatch ? block.indexOf(respMatch[0]) : block.length;

      // Limpa cabeçalho da questão do enunciado
      let stmt = block.substring(0, stmtEnd)
        .replace(/(?:\*\*|##)?[ \t]*Quest[aã]o(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?\d+(?:\.\d+)*\]?[^\n]*\n?/i, '')
        .replace(/(?:^|\n)[ \t]*\d{1,3}[ \t]*[).][^\n]*\n?/, '')
        .trim();
      if (!stmt || stmt.length < 5) return;

      const expectedAnswer = respMatch ? respMatch[1].trim() : '';

      // Extrai explicação
      let exp = cleanQuestionExplanation(extractLabeledSection(block));
      const questionIsEssay = autoEssay
        ? /(?:dissertativa|disserte|discuta|explique\s+detalhadamente|relacione|compare\s+criticamente|analise\s+criticamente)/i.test(block)
        : !!isEssay;

      questions.push({ id, statement: stmt, options: [], explanation: exp, expectedAnswer, isOpen: true, isEssay:questionIsEssay });
    } catch(e) {}
  });

  return { questions, summary: '' };
};

const parseFlashcards = (text, namespace='') => {
  const norm = String(text || '').replace(/\r\n/g, '\n');
  const questions = [];
  let qCount = 0;

  const pipeLines = norm.split('\n').map(l => l.trim()).filter(l =>
    l.includes('|') && !/^question\s*\|/i.test(l) && !/^pergunta\s*\|/i.test(l)
  );
  if (pipeLines.length >= 1 && !/(?:^|\n)\s*(?:##\s*)?Flashcard\s+\d+/i.test(norm)) {
    pipeLines.forEach(line => {
      const parts = line.split('|');
      if (parts.length < 2) return;
      const statement = parts.shift().trim();
      const rawAnswer = parts.join('|').trim();
      if (!statement || !rawAnswer) return;
      const [shortAnswer, ...expParts] = rawAnswer.split(/<br\s*\/?><br\s*\/?>/i);
      const rawId = `${++qCount}`;
      const id = namespace ? `${namespace}_${rawId}` : rawId;
      questions.push({
        id,
        statement,
        expectedAnswer: shortAnswer.trim(),
        explanation: cleanQuestionExplanation(expParts.join('<br><br>').trim()),
        options: [],
        isFlashcard: true,
      });
    });
    return { questions, summary:'' };
  }

  const blocks = norm
    .split(/(?=(?:^|\n)[ \t]*(?:(?:\*\*|##)[ \t]*)?Flashcard(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?\d|(?:^|\n)[ \t]*Flashcard\s+\d+)/im)
    .filter(b => b.trim());

  blocks.forEach(block => {
    try {
      const idM = block.match(/Flashcard(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?(\d+(?:\.\d+)*)\]?/i);
      const rawId = idM ? idM[1] : `${++qCount}`;
      const id = namespace ? `${namespace}_${rawId}` : rawId;
      const questionM = block.match(/Pergunta:\s*([\s\S]*?)(?:\nResposta:|\nVerso:|\nExplica[çc][aã]o:|\n---|$)/i);
      const answerM = block.match(/Resposta:\s*([\s\S]*?)(?:\nExplica[çc][aã]o:|\n---|$)/i);
      const expM = block.match(/Explica[çc][aã]o:\s*([\s\S]*?)(?:\n---|$)/i);
      let statement = questionM?.[1]?.trim() || '';
      let expectedAnswer = answerM?.[1]?.trim() || '';
      let explanation = expM?.[1]?.trim() || '';
      if (!statement || !expectedAnswer) return;
      const answerParts = expectedAnswer.split(/<br\s*\/?><br\s*\/?>/i);
      if (!explanation && answerParts.length > 1) {
        expectedAnswer = answerParts.shift().trim();
        explanation = answerParts.join('<br><br>').trim();
      }
      questions.push({
        id,
        statement,
        expectedAnswer,
        explanation: cleanQuestionExplanation(explanation),
        options: [],
        isFlashcard: true,
      });
    } catch(e) {}
  });

  return { questions, summary:'' };
};

const CLOZE_RE = /\{\{c\d+::([\s\S]*?)(?:::([^{}]*))?\}\}/g;
const hasClozeMarkup = (text = '') => /\{\{c\d+::[\s\S]+?\}\}/i.test(String(text || ''));
const clozeTextToPrompt = (text = '') => String(text || '').replace(CLOZE_RE, (_, answer, hint) => `[${hint?.trim() || '...'}]`).trim();
const extractClozeAnswers = (text = '') => {
  const answers = [];
  String(text || '').replace(CLOZE_RE, (_, answer) => {
    const clean = htmlishToText(answer).trim();
    if (clean && !answers.includes(clean)) answers.push(clean);
    return '';
  });
  return answers.join(' / ');
};

const parseClozeCards = (text, namespace='') => {
  const norm = String(text || '').replace(/\r\n/g, '\n');
  const questions = [];
  let qCount = 0;
  const blocks = norm
    .split(/(?=(?:^|\n)[ \t]*(?:(?:\*\*|##)[ \t]*)?Cloze(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?\d|(?:^|\n)[ \t]*Cloze\s+\d+)/im)
    .filter(b => b.trim());

  const sourceBlocks = blocks.length ? blocks : hasClozeMarkup(norm) ? norm.split(/\n---+\n?/).filter(Boolean) : [];
  sourceBlocks.forEach(block => {
    try {
      const idM = block.match(/Cloze(?:[ \t]*(?:n[ºo]\.?)?)?[ \t]*[:#\-–—]?[ \t]*\[?(\d+(?:\.\d+)*)\]?/i);
      const rawId = idM ? idM[1] : `${++qCount}`;
      const id = namespace ? `${namespace}_${rawId}` : rawId;
      const textM = block.match(/(?:Texto|Text|Frase):\s*([\s\S]*?)(?:\n(?:Extra|Explica[çc][aã]o|Notas(?:\/L[óo]gica)?):|\n---|$)/i);
      const extraM = block.match(/(?:Extra|Explica[çc][aã]o|Notas(?:\/L[óo]gica)?):\s*([\s\S]*?)(?:\n---|$)/i);
      const clozeText = (textM?.[1] || block.match(/(\{\{c\d+::[\s\S]+?\}\}[\s\S]*?)(?:\n---|$)/i)?.[1] || '').trim();
      if (!hasClozeMarkup(clozeText)) return;
      const expectedAnswer = extractClozeAnswers(clozeText);
      if (!expectedAnswer) return;
      questions.push({
        id,
        statement:clozeTextToPrompt(clozeText),
        clozeText,
        expectedAnswer,
        explanation:cleanQuestionExplanation(extraM?.[1] || ''),
        options:[],
        isFlashcard:true,
        isCloze:true,
      });
    } catch(e) {}
  });

  return { questions, summary:'' };
};

const stripLooseMarkdownAsterisks = (text = '') => {
  return String(text || '').replace(/\*/g, '');
};

const extractQuickSection = (text = '', heading = '') => {
  const raw = String(text || '').replace(/\r\n/g, '\n');
  const escaped = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(`(?:^|\\n)#{2,4}\\s*${escaped}\\s*\\n([\\s\\S]*?)(?=(?:^|\\n)#{2,4}\\s*(?:Aula\\s+r[aá]pida|Explica[çc][aã]o|Quest[õo]es|Flashcards)\\b|$)`, 'i');
  return (raw.match(re)?.[1] || '').trim();
};

const extractQuickLesson = (text = '') => {
  const raw = String(text || '').replace(/\r\n/g, '\n');
  const match = raw.match(/(?:^|\n)##\s*Aula\s+r[aá]pida\s*\n([\s\S]*?)(?=(?:^|\n)##\s*(?:Quest[õo]es|Flashcards)\b|$)/i)
    || raw.match(/(?:^|\n)##\s*Explica[çc][aã]o\s*\n([\s\S]*?)(?=(?:^|\n)##\s*(?:Quest[õo]es|Flashcards)\b|$)/i);
  const lesson = (match?.[1] || extractQuickSection(raw, 'Aula rápida') || '').trim();
  return stripLooseMarkdownAsterisks(lesson.replace(/:\*/g, ':')).replace(/\n{3,}/g, '\n\n').trim();
};

const extractQuickTitle = (text = '', fallback = '') => {
  const raw = String(text || '').replace(/\r\n/g, '\n');
  const match = raw.match(/(?:^|\n)##\s*T[íi]tulo\s*\n([\s\S]*?)(?=(?:^|\n)##\s*(?:Foco|Aula\s+r[aá]pida|Explica[çc][aã]o)\b|$)/i);
  return stripLooseMarkdownAsterisks((match?.[1] || fallback || '').trim().split('\n')[0] || '').replace(/^["'“”]+|["'“”]+$/g, '').trim();
};

const extractQuickIntent = (text = '', fallback = '') => {
  const raw = String(text || '').replace(/\r\n/g, '\n');
  const match = raw.match(/(?:^|\n)##\s*Foco\s*\n([\s\S]*?)(?=(?:^|\n)##\s*(?:Aula\s+r[aá]pida|Explica[çc][aã]o)\b|$)/i);
  return stripLooseMarkdownAsterisks((match?.[1] || fallback || '').trim()).replace(/\n{3,}/g, '\n\n').trim();
};

const buildQuickLessonPrompt = ({ context='', explanationLength='essential' }) => {
  const lengthRule = {
    essential: `PROFUNDIDADE: Nível 1 — resposta curta e ultra-direta.
- Alvo: 120 a 220 palavras.
- Foque no mecanismo/ideia que resolve a dúvida e em 2 a 4 pontos essenciais.
- Use no máximo 1 subtítulo "###" além do texto principal.
- Corte exemplos longos, contexto histórico e rodeios.`,
    balanced: `PROFUNDIDADE: Nível 2 — explicação enxuta com raciocínio.
- Alvo: 220 a 380 palavras.
- Explique o mecanismo e traga exemplos/pegadinhas apenas quando ajudarem.
- Use subtítulos "###" quando organizar melhor.`,
    complete: `PROFUNDIDADE: Nível 3 — mini-aula mais completa.
- Alvo: 380 a 650 palavras.
- Inclua contexto, mecanismo, implicações clínicas e exceções importantes.
- Ainda assim, não transforme a dúvida em aula genérica.`
  }[explanationLength] || '';
  return `
Você vai criar a primeira parte de uma Centelha do Saber em português brasileiro.

DÚVIDA/MATERIAL DO USUÁRIO:
${context || 'Sem contexto. Peça mais contexto implicitamente criando uma explicação curta do tema provável.'}

OBJETIVO:
- Entender exatamente qual lacuna o usuário quer resolver.
- Definir um título curto e específico.
- Explicar a lacuna em uma mini-aula objetiva, clínica e high-yield.

REGRAS:
- Não gere questões e não gere flashcards neste request.
- Não transforme a dúvida em uma aula genérica.
- Seja didático, mas respeite rigorosamente o nível escolhido.
- Use parágrafos curtos.
- Use subtítulos de nível 3 com "###" quando ajudar.
- Use tópicos com hífen quando necessário.
- Não use asteriscos, negrito ou itálico.
- Se a dúvida veio de conversa leiga, inclua uma forma simples de explicar sem perder precisão.

${lengthRule}

FORMATO OBRIGATÓRIO:
## Título
[título curto, sem aspas]

## Foco
[uma frase dizendo exatamente o que o usuário queria entender]

## Aula rápida
[mini-aula em markdown]
`.trim();
};

const buildQuickPracticePrompt = ({ title='', context='', lesson='', intent='', settings={} }) => {
  const alts = Number(settings.numAlternatives || 5) === 4
    ? 'A) [alternativa]\nB) [alternativa]\nC) [alternativa]\nD) [alternativa]'
    : 'A) [alternativa]\nB) [alternativa]\nC) [alternativa]\nD) [alternativa]\nE) [alternativa]';
  const styleInst = {
    clinical:'Prefira vinhetas clínicas curtas e cobráveis, com dado discriminativo real e sem entregar diagnóstico/conduta no enunciado.',
    direct:'Prefira perguntas diretas com alvo estreito: mecanismo, critério, exceção, comparação ou consequência prática.',
    mixed:'Misture casos clínicos curtos e perguntas diretas.',
  }[settings.questionStyle || 'mixed'];
  const adminExplanationFormat = settings.adminQuestionExplanations ? `
FORMATO ADMIN PARA EXPLICAÇÕES DAS QUESTÕES:
- Separe a explicação em "Aula:" e "Alternativas:".
- Aula: explique o conceito de modo suficiente para o aluno entender e acertar a questão.
- Alternativas: use [[ALT:A]], [[ALT:B]], [[ALT:C]], [[ALT:D]] e [[ALT:E]] quando houver E.
- Em [[ALT:A]], explique por que a correta está certa. Nas demais, explique o erro específico em poucas palavras.
- A explicação da alternativa precisa ficar presa ao conteúdo dela, pois o site embaralha alternativa + explicação juntas.` : '';
  return `
Você vai criar a parte ativa de uma Centelha do Saber em português brasileiro.

TEMA:
${title}

FOCO IDENTIFICADO:
${intent || title}

CONTEXTO DO USUÁRIO:
${context || 'Sem contexto adicional. Explique o tema do zero, mas sem fugir do foco.'}

AULA JÁ GERADA:
${lesson || 'Sem aula enviada. Use o contexto e o foco acima.'}

OBJETIVO:
- Criar uma quantidade compacta de questões de fixação que testem se o usuário realmente entendeu essa lacuna.
- Criar flashcards obrigatórios, atômicos e exportáveis ao Anki para impedir que a lacuna volte.
- Não reescrever a aula. Gere apenas questões e flashcards.

REGRAS DAS QUESTÕES:
- ${styleInst}
- Gere de 4 a 6 questões. A IA decide a quantidade ideal conforme a complexidade da lacuna.
- Cada questão deve voltar ao problema central do usuário. Não cobre curiosidades periféricas só porque apareceram na explicação.
- Priorize mecanismos causais, decisões práticas, pegadinhas diretamente relacionadas e reconstrução ativa do raciocínio.
- Evite perguntas óbvias, decorebas inúteis e alternativas absurdas.
- Em casos clínicos, inclua apenas dados que mudam o raciocínio: contexto, tempo de evolução, achados positivos e negativos úteis. Não use "clássico", "característico", "destacando-se por" ou frases que entreguem a resposta.
- O caso deve terminar em uma decisão clara: diagnóstico, próxima conduta, fármaco, efeito adverso, mecanismo, exame ou contraindicação.
- Em perguntas diretas, evite "O que é X?", "qual a principal característica?" ou "qual conduta?" sem escopo. A pergunta deve dizer exatamente que tipo de resposta espera.
- Pergunta direta boa deve diferenciar algo: mecanismo vs efeito, regra vs exceção, critério obrigatório vs achado inespecífico, ou fármacos/diagnósticos próximos.
- Questões com alternativas devem ter exatamente ${Number(settings.numAlternatives || 5)} alternativas no formato:
${alts}
- Depois de cada questão inclua "Gabarito: X" e "Explicação:".
${adminExplanationFormat}

REGRAS DOS FLASHCARDS:
- Gere de 5 a 8 flashcards. Nunca gere menos de 5.
- Crie somente a quantidade útil para memorizar a lacuna, sem pilha excessiva.
- Cada flashcard deve ter um alvo claro de recuperação, ser autossuficiente e não redundante.
- "Atômico" não significa separar tudo: agrupe 2 a 4 itens quando eles formam uma unidade natural, como principais efeitos adversos, monitorização obrigatória, tríade ou fármacos que compartilham uma interação.
- Separe em cards diferentes quando os itens têm mecanismos, decisões ou explicações diferentes.
- Se a pergunta disser "dois", "três", "(2)" ou "(3)", a resposta deve ter exatamente essa quantidade.
- Não use "cite um" com resposta contendo várias opções. Se quer conjunto, pergunte o conjunto; se quer um exemplo, responda um exemplo.
- Use dificuldade desejável: a pergunta deve exigir recuperação ativa, não reconhecimento passivo.
- Zero ambiguidade: a pergunta deve ter contexto suficiente para uma única resposta justa.
- Teste de previsibilidade: se uma pessoa que entendeu o tema não conseguir adivinhar o tipo exato de resposta esperada, reescreva a pergunta. Proibido fazer perguntas abertas genéricas como "O que é X?" quando a resposta seria "doença autoimune", "condição crônica" ou outra definição ampla.
- Evite perguntas de sim/não; transforme em uma pergunta que peça a informação substantiva.
- Toda pergunta deve terminar com ponto de interrogação.
- Resposta curta: 1 a 6 palavras ou, em conjuntos naturais, 2 a 4 itens curtos.
- Depois da resposta curta, a explicação deve ensinar por que aquela resposta é correta ou como ela acontece. Ela não pode repetir a resposta com mais palavras nem virar curso.
- Se o card perguntar efeitos colaterais, a resposta lista os efeitos e a explicação diz por que eles ocorrem ou por que importam. Se perguntar uma escolha/conduta, a explicação diz qual propriedade do fármaco ou do quadro clínico justifica aquela opção.
- Explicação ruim: "é usado porque é eficaz/primeira linha/indicado". Explicação boa: conecta fármaco/quadro clínico → propriedade relevante → motivo da resposta.
- Não faça cartões que cobrem detalhes inúteis; faça cartões que, juntos, permitam revisar a dúvida inteira depois.

FORMATO FINAL OBRIGATÓRIO:
## Questões
## Questão 1
[enunciado]
${alts}
Gabarito: A
Explicação:${settings.adminQuestionExplanations ? `
Aula:
[aula curta e completa sobre o tema]

Alternativas:
[[ALT:A]]
[por que a alternativa A está correta]

[[ALT:B]]
[por que a alternativa B está errada]

[[ALT:C]]
[por que a alternativa C está errada]

[[ALT:D]]
[por que a alternativa D está errada]

[[ALT:E]]
[por que a alternativa E está errada, se existir]` : ' [explicação]'}

## Flashcards
## Flashcard 1
Pergunta: [pergunta objetiva e específica?]
Resposta: [resposta curta, poucas palavras]
Explicação: [explicação curta do porquê/como da resposta]
---
`.trim();
};

const renderQuickLesson = (lesson = '', darkMode = false) => {
  const lines = stripLooseMarkdownAsterisks(lesson).split('\n');
  const elements = [];
  let i = 0;
  while (i < lines.length) {
    const raw = lines[i] || '';
    const line = raw.trim();
    const heading = line.match(/^#{2,4}\s+(.+)$/);
    if (heading) {
      elements.push(
        <h3 key={`qh-${i}`} className={`text-base font-bold mt-6 mb-2 ${darkMode?'text-yellow-300':'text-yellow-700'}`}>
          {parseHtmlText(heading[1].trim())}
        </h3>
      );
      i++;
      continue;
    }
    if (/^\s*[-•]\s/.test(raw)) {
      const items = [];
      while (i < lines.length && /^\s*[-•]\s/.test(lines[i] || '')) {
        items.push((lines[i] || '').replace(/^\s*[-•]\s/, '').trim());
        i++;
      }
      elements.push(
        <ul key={`qul-${i}`} className={`list-disc ml-5 space-y-1.5 my-3 text-base leading-relaxed ${darkMode?'text-gray-300':'text-gray-700'}`}>
          {items.map((item, idx) => <li key={idx}>{parseHtmlText(item)}</li>)}
        </ul>
      );
      continue;
    }
    if (!line) {
      elements.push(<div key={`qsp-${i}`} className="h-2"/>);
      i++;
      continue;
    }
    elements.push(
      <p key={`qp-${i}`} className={`text-base leading-relaxed ${darkMode?'text-gray-200':'text-gray-800'}`}>
        {parseHtmlText(line)}
      </p>
    );
    i++;
  }
  return elements;
};

const parseGeneratedQuestionsByTypes = (text, namespace='', types=['direct']) => {
  const selectedTypes = types || ['direct'];
  let allQuestions = [];
  if (selectedTypes.some(t => ['direct','vof','cespe'].includes(t))) {
    const p = parseData(text, namespace);
    allQuestions = [...allQuestions, ...p.questions];
  }
  if (selectedTypes.includes('open')) {
    const p = parseOpenQuestions(text, namespace, selectedTypes.includes('essay') ? 'auto' : false);
    allQuestions = [...allQuestions, ...p.questions];
  } else if (selectedTypes.includes('essay')) {
    const p = parseOpenQuestions(text, namespace, true);
    allQuestions = [...allQuestions, ...p.questions.map(q => ({...q, isEssay:true}))];
  }
  if (selectedTypes.includes('flashcard')) {
    const p = parseFlashcards(text, namespace);
    allQuestions = [...allQuestions, ...p.questions];
  }
  if (selectedTypes.includes('cloze')) {
    const p = parseClozeCards(text, namespace);
    allQuestions = [...allQuestions, ...p.questions];
  }
  return { questions:allQuestions, summary:parseData(text).summary || '' };
};

const questionsToGenerationText = (questions = []) => questions.map((q, index) => {
  if (q.isCloze) {
    return `## Cloze ${index + 1}
Texto: ${q.clozeText || q.statement || ''}
Extra: ${q.explanation || ''}
---`;
  }
  if (q.isFlashcard) {
    return `## Flashcard ${index + 1}
Pergunta: ${q.statement || ''}
Resposta: ${q.expectedAnswer || ''}
Explicação: ${q.explanation || ''}
---`;
  }
  if (q.isOpen) {
    return `## Questão ${index + 1}
${q.statement || ''}
Resposta esperada: ${q.expectedAnswer || ''}
Explicação: ${q.explanation || ''}
---`;
  }
  const correct = (q.options || []).find(o => o.isCorrect);
  const distractors = (q.options || []).filter(o => !o.isCorrect);
  const ordered = [correct, ...distractors].filter(Boolean).slice(0, 5);
  const options = ordered.map((opt, i) => `${'ABCDE'[i]}) ${opt.text || ''}`).join('\n');
  const structuredExplanation = ordered.some(opt => opt?.explanation)
    ? `Aula:
${q.explanationParts?.lesson || q.explanation || ''}

Alternativas:
${ordered.map((opt, i) => `[[ALT:${'ABCDE'[i]}]]
${opt.explanation || ''}`).join('\n\n')}`
    : (q.explanation || '');
  return `## Questão ${index + 1}
${q.statement || ''}
${options}
Alternativa correta: A
Explicação:
${structuredExplanation}
---`;
}).join('\n\n');

// Carrega KaTeX uma vez para renderização de LaTeX
let _katexLoaded = false;
const ensureKatex = () => {
  if (_katexLoaded || window.katex) { _katexLoaded = true; return Promise.resolve(); }
  return new Promise((res, rej) => {
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = 'https://cdnjs.cloudflare.com/ajax/libs/KaTeX/0.16.9/katex.min.css';
    document.head.appendChild(link);
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/KaTeX/0.16.9/katex.min.js';
    s.onload = () => { _katexLoaded = true; res(); };
    s.onerror = rej;
    document.head.appendChild(s);
  });
};

// Componente que renderiza uma expressão LaTeX inline
const TexInline = ({ src, display=false }) => {
  const ref = useRef(null);
  useEffect(() => {
    if (!ref.current) return;
    ensureKatex().then(() => {
      try {
        window.katex.render(src, ref.current, { throwOnError: false, displayMode: display });
      } catch(e) { if (ref.current) ref.current.textContent = src; }
    }).catch(() => { if (ref.current) ref.current.textContent = src; });
  }, [src, display]);
  return <span ref={ref} style={display ? {display:'block',textAlign:'center',margin:'8px 0'} : {display:'inline'}}/>;
};

// Render rich text: bold, italic, grifo de prova (==texto==), LaTeX e line breaks
const renderRichText = (text, multiline = false) => {
  if (!text) return null;

  // Tokeniza o texto em segmentos: $$...$$ (display), $...$ (inline), **...**, <b>, <i>, <br>, texto
  const tokenize = (str) => {
    const tokens = [];
    // Regex: $$...$$, $...$, ==...==, **...**, *...*, _..._, <b>...</b>, <i>...</i>, <br/>
    // Nota: [\s\S] para capturar múltiplas linhas no bold
    const re = /(\$\$[\s\S]+?\$\$|\$[^$\n]+?\$|==[^=\n]+?==|\*\*[\s\S]*?\*\*|\*[^*\n]+?\*|(^|[^\w])_([^_\n_](?:[^_\n]*?[^_\n_])?)_(?=$|[^\w])|<b>[\s\S]*?<\/b>|<i>[\s\S]*?<\/i>|<br\s*\/?>)/g;
    let last = 0, m;
    while ((m = re.exec(str)) !== null) {
      if (m.index > last) tokens.push({ type: 'text', val: str.slice(last, m.index) });
      const v = m[0];
      if (m[3] !== undefined) {
        if (m[2]) tokens.push({ type: 'text', val: m[2] });
        tokens.push({ type: 'italic', val: m[3] });
      }
      else if (v.startsWith('$$')) tokens.push({ type: 'tex-display', val: v.slice(2, -2).trim() });
      else if (v.startsWith('$'))  tokens.push({ type: 'tex-inline', val: v.slice(1, -1).trim() });
      else if (v.startsWith('==')) tokens.push({ type: 'highlight', val: v.slice(2, -2).trim() });
      else if (v.startsWith('**')) tokens.push({ type: 'bold', val: v.slice(2, -2) });
      else if (v.startsWith('*') && !v.startsWith('**')) tokens.push({ type: 'italic', val: v.slice(1, -1) });
      else if (v.startsWith('<b>'))tokens.push({ type: 'bold', val: v.slice(3, -4) });
      else if (v.startsWith('<i>'))tokens.push({ type: 'italic', val: v.slice(3, -4) });
      else if (v.match(/^<br/))   tokens.push({ type: 'br' });
      last = m.index + v.length;
    }
    if (last < str.length) tokens.push({ type: 'text', val: str.slice(last) });
    return tokens;
  };

  const renderTokens = (tokens, keyPrefix) =>
    tokens.map((tok, i) => {
      const k = `${keyPrefix}-${i}`;
      switch (tok.type) {
        case 'bold':        return <strong key={k} className="font-bold">{tok.val}</strong>;
        case 'italic':      return <em key={k}>{tok.val}</em>;
        case 'highlight':   return <mark key={k} title="Ponto de prova" className="rounded-sm bg-yellow-200 px-1 py-0.5 font-medium text-gray-900 dark:bg-yellow-700/60 dark:text-yellow-50">{renderTokens(tokenize(tok.val), `${k}-highlight`)}</mark>;
        case 'br':          return <br key={k}/>;
        case 'tex-inline':  return <TexInline key={k} src={tok.val} display={false}/>;
        case 'tex-display': return <TexInline key={k} src={tok.val} display={true}/>;
        default:            return <span key={k}>{tok.val}</span>;
      }
    });

  if (!multiline) {
    return <React.Fragment>{renderTokens(tokenize(text), 'r')}</React.Fragment>;
  }
  const lines = text.split('\n');
  return lines.map((line, li) => (
    <React.Fragment key={li}>
      {renderTokens(tokenize(line), `l${li}`)}
      {li < lines.length - 1 && <br/>}
    </React.Fragment>
  ));
};

// Aliases para compatibilidade
const parseHtmlText     = (text) => renderRichText(text, false);
const parseHtmlTextChat = (text) => renderRichText(text, true);


// Retorna os valores de blocks como array seguro, independente do formato salvo
const blockValues = (blocks) => {
  if (!blocks) return [];
  if (Array.isArray(blocks)) return blocks;
  if (typeof blocks === 'object') {
    return Object.values(blocks).map(b => ({
      ...b,
      questions: Array.isArray(b?.questions) ? b.questions : [],
      answers:   (b?.answers && !Array.isArray(b.answers)) ? b.answers : {},
    }));
  }
  return [];
};
// Converte o raw do Firestore (qualquer formato) para estrutura canônica:
// { [subject]: { [topic]: { main: Aula[], bonus: Aula[] } } }
const parseVideoaulasData = (raw) => {
  if (!raw || !Object.keys(raw).length) return {};
  const result = {};
  Object.entries(raw).forEach(([subj, rawTopics]) => {
    const sortedTopics = Object.keys(rawTopics).sort((a, b) => getSubtopicOrder(a) - getSubtopicOrder(b));
    result[subj] = {};
    // Primeiro passo: agrupar chaves com ⭐ na sua base (formato antigo do Firestore)
    const merged = {};
    sortedTopics.forEach(key => {
      const val = rawTopics[key];
      const isBonus = /⭐/.test(key);
      const baseKey = key.replace(/\s*⭐\s*$/, '').trim();
      if (!merged[baseKey]) merged[baseKey] = { main: [], bonus: [] };
      if (Array.isArray(val)) {
        if (isBonus) merged[baseKey].bonus.push(...val);
        else         merged[baseKey].main.push(...val);
      } else if (val && typeof val === 'object') {
        merged[baseKey].main.push(...(val['Aulas Principais'] || []));
        merged[baseKey].bonus.push(...(val['Bônus'] || []));
      }
    });
    // Ordenar keys mescladas
    const sortedMerged = Object.keys(merged).sort((a, b) => getSubtopicOrder(a) - getSubtopicOrder(b));
    sortedMerged.forEach(k => { result[subj][k] = merged[k]; });
  });
  return result;
};

// Extrai array flat de aulas de qualquer formato de cats
const extractAulas = (cats) => {
  if (!cats) return [];
  if (Array.isArray(cats)) return cats;
  const main = cats['Aulas Principais'] || cats.main || [];
  const bonus = cats['Bônus'] || cats.bonus || [];
  if (main.length || bonus.length) return [...main, ...bonus];
  return Object.values(cats).filter(Array.isArray).flat();
};

const parseLessonDurationSeconds = (aula = {}) => {
  const direct = Number(aula.duration_seconds || aula.durationSeconds || 0);
  if (Number.isFinite(direct) && direct > 0) return direct;
  const raw = String(aula.duration_formatted || aula.duration || '').trim().toLowerCase();
  if (!raw) return 0;
  if (/^\d{1,2}:\d{2}(?::\d{2})?$/.test(raw)) {
    const parts = raw.split(':').map(n => Number(n) || 0);
    return parts.length === 3
      ? parts[0] * 3600 + parts[1] * 60 + parts[2]
      : parts[0] * 60 + parts[1];
  }
  const h = raw.match(/(\d+(?:[.,]\d+)?)\s*h/);
  const m = raw.match(/(\d+(?:[.,]\d+)?)\s*(?:m|min)/);
  const s = raw.match(/(\d+(?:[.,]\d+)?)\s*s/);
  const toNum = (match) => match ? Number(String(match[1]).replace(',', '.')) || 0 : 0;
  return Math.round(toNum(h) * 3600 + toNum(m) * 60 + toNum(s));
};

const totalLessonSeconds = (lessons = []) =>
  lessons.reduce((sum, aula) => sum + parseLessonDurationSeconds(aula), 0);

const formatCourseDuration = (seconds = 0) => {
  const total = Math.round(Number(seconds) || 0);
  if (total <= 0) return '';
  const hours = Math.floor(total / 3600);
  const minutes = Math.round((total % 3600) / 60);
  if (hours <= 0) return `${Math.max(1, minutes)}min`;
  if (minutes === 0) return `${hours}h`;
  return `${hours}h${String(minutes).padStart(2, '0')}`;
};

// Sort subjects by course chronogram order
const sortSubjects = (subjects) =>
  [...subjects].sort((a, b) => {
    const ai = SUBJECT_ORDER.findIndex(s => a.toLowerCase().includes(s.toLowerCase()) || s.toLowerCase().includes(a.toLowerCase()));
    const bi = SUBJECT_ORDER.findIndex(s => b.toLowerCase().includes(s.toLowerCase()) || s.toLowerCase().includes(b.toLowerCase()));
    return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
  });

const libraryOrderValue = (item) => Number.isFinite(Number(item?.sortOrder))
  ? Number(item.sortOrder)
  : -(Number(item?.createdAt || item?.id) || 0);
const sortLibraryItems = (items) => [...items].sort((a,b)=>{
  const d = libraryOrderValue(a) - libraryOrderValue(b);
  if (d) return d;
  return String(a?.title || '').localeCompare(String(b?.title || ''), 'pt');
});

// Short display name for a topic key: "GIN 6 - IST" → "Ist"
const shortTopicName = (key) => {
  const clean = key.replace(/^[A-ZÁÉÍÓÚ]{2,8}\s*\d+\s*[-–]\s*/i, '').trim();
  const t = clean.charAt(0).toUpperCase() + clean.slice(1).toLowerCase();
  return t.length > 32 ? t.substring(0, 31) + '…' : (t || key);
};

const courseLessonDisplayTitle = (aula = {}) =>
  cleanCourseOrgLabel(aula.display_title || aula.ai_catalog?.cleanTitle || cleanAulaTitle(aula.title || ''));

const flattenCourseLessons = (raw) => {
  const data = parseVideoaulasData(raw || {});
  return sortSubjects(Object.keys(data)).flatMap(subject =>
    Object.entries(data[subject] || {}).flatMap(([topic, cats]) => {
      const groups = [
        { cat:'main', label:'Aulas', items:cats.main || [] },
        { cat:'bonus', label:'Bônus', items:cats.bonus || [] },
      ];
      return groups.flatMap(group => group.items.map((aula, index) => {
        const id = getAulaId(aula) || `${subject}::${topic}::${group.cat}::${index}`;
        return {
          id,
          docId:aula.doc_id || id,
          subject,
          topic,
          cat:group.cat,
          catLabel:group.label,
          index,
          aula,
          title:courseLessonDisplayTitle(aula),
          topicTitle:aula.display_topic || shortTopicName(topic),
          durationSeconds:aula.duration_seconds || 0,
          duration:aula.duration_formatted || '',
        };
      }));
    })
  );
};

const applyCourseOrgProposalToVideoData = (raw, proposal) => {
  const normalized = normalizeCourseOrgProposal(proposal);
  if (!normalized?.subjects?.length || !raw || !Object.keys(raw).length) return raw;
  const allLessons = flattenCourseLessons(raw);
  const byId = new Map();
  const byTitle = new Map();
  const addTitleMatch = (value, lesson) => {
    const key = cleanAulaTitle(value || '');
    if (!key || byTitle.has(key)) return;
    byTitle.set(key, lesson);
  };
  allLessons.forEach(lesson => {
    [lesson.docId, lesson.id, getAulaId(lesson.aula)].filter(Boolean).forEach(id => byId.set(String(id), lesson));
    [
      lesson.title,
      lesson.aula?.title,
      lesson.aula?.display_title,
      lesson.aula?.ai_catalog?.cleanTitle,
      lesson.aula?.ai_catalog?.originalTitle,
    ].forEach(value => addTitleMatch(value, lesson));
  });
  const findSourceLesson = (proposalLesson) => {
    const idHit = byId.get(String(proposalLesson?.lessonId || ''));
    if (idHit) return idHit;
    const candidates = [
      proposalLesson?.title,
      proposalLesson?.originalTitle,
      proposalLesson?.cleanTitle,
    ];
    for (const value of candidates) {
      const hit = byTitle.get(cleanAulaTitle(value || ''));
      if (hit) return hit;
    }
    return null;
  };
  const used = new Set();
  const result = {};
  normalized.subjects.forEach(subjectProposal => {
    if (!subjectProposal?.subject) return;
    result[subjectProposal.subject] = result[subjectProposal.subject] || {};
    (subjectProposal.modules || []).forEach((module, moduleIndex) => {
      const topicKey = `${String(moduleIndex + 1).padStart(2, '0')} - ${module.title || `Módulo ${moduleIndex + 1}`}`;
      result[subjectProposal.subject][topicKey] = { 'Aulas Principais': [], 'Bônus': [] };
      (module.lessons || []).forEach((proposalLesson, lessonIndex) => {
        const source = findSourceLesson(proposalLesson);
        if (!source) return;
        const sourceSubject = getManualCorrectedCourseSubjectName({
          ...source.aula,
          title:source.title || source.aula?.title || '',
          subject:source.subject || source.aula?.subject || '',
          aula:source.aula,
        });
        if (normalizeTextKey(sourceSubject) !== normalizeTextKey(normalizeCourseSubjectName(subjectProposal.subject))) return;
        if (used.has(source.id) || used.has(source.docId) || used.has(getAulaId(source.aula))) return;
        used.add(source.id);
        if (source.docId) used.add(source.docId);
        if (getAulaId(source.aula)) used.add(getAulaId(source.aula));
        result[subjectProposal.subject][topicKey]['Aulas Principais'].push({
          ...source.aula,
          display_title:proposalLesson.title || source.title,
          display_topic:module.title || source.topicTitle,
          display_order:lessonIndex + 1,
          display_plan_order:moduleIndex * 1000 + lessonIndex + 1,
          display_proposal_lesson_id:proposalLesson.lessonId || source.docId || source.id,
        });
      });
    });
  });
  allLessons.forEach(lesson => {
    if (used.has(lesson.id) || used.has(lesson.docId)) return;
    if (!result[lesson.subject]) result[lesson.subject] = {};
    if (!result[lesson.subject][lesson.topic]) result[lesson.subject][lesson.topic] = { 'Aulas Principais': [], 'Bônus': [] };
    const bucket = lesson.cat === 'bonus' ? 'Bônus' : 'Aulas Principais';
    result[lesson.subject][lesson.topic][bucket].push(lesson.aula);
  });
  return result;
};

const ADMIN_COURSE_TOPIC_QUESTION_MAX = 30;

const getCourseVqQuestionPlan = ({ durationSecs = 0, suggestedQ = 10, isAdmin = false, maxPerBlock = 20 }) => {
  if (isAdmin && durationSecs > 0) {
    const totalQ = Math.max(1, Math.ceil(durationSecs / 60));
    const qPerBlock = Math.min(ADMIN_COURSE_TOPIC_QUESTION_MAX, totalQ);
    return { totalQ, qPerBlock, numBlocks:Math.ceil(totalQ / qPerBlock), adminMinuteRule:true };
  }
  const raw = durationSecs > 0 ? Math.ceil(durationSecs / 120) : (suggestedQ || 10);
  const totalQ = Math.max(10, Math.round(raw / 10) * 10);
  const qPerBlock = Math.min(maxPerBlock, totalQ);
  return { totalQ, qPerBlock, numBlocks:Math.ceil(totalQ / qPerBlock), adminMinuteRule:false };
};

