  const [courseCatalogRun, setCourseCatalogRun] = useState({ running:false, paused:false, stopping:false, current:0, total:0, logs:[] });
  const [courseCatalogStats, setCourseCatalogStats] = useState({ loading:false, rows:[], total:0, pending:0 });
  const [courseOrgRun, setCourseOrgRun] = useState({ running:false, current:0, total:0, logs:[] });
  const [courseOrgProposal, setCourseOrgProposal] = useState(null);
  const [courseOrgSelectedSubject, setCourseOrgSelectedSubject] = useState('');
  const courseManualRepairAppliedRef = useRef(false);
  const courseGlobalOrgPublishedRef = useRef(false);
  const courseCatalogControlRef = useRef({ paused:false, stop:false });
  const courseCatalogLogRef = useRef(null);
  const videoMainScrollRef = useRef(null);

  const scrollPageToTop = useCallback((behavior = 'smooth') => {
    const scroll = () => {
      window.scrollTo({ top:0, behavior });
      if (videoMainScrollRef.current) {
        videoMainScrollRef.current.scrollTo({ top:0, behavior });
      }
    };
    requestAnimationFrame(scroll);
    setTimeout(scroll, 80);
  }, []);

  const activeAulaScrollId = getAulaId(activeAula);
  const vqAulaScrollId = getAulaId(vqAula);
  useEffect(() => {
    scrollPageToTop();
  }, [
    scrollPageToTop,
    view,
    activeSubjectId,
    activeTopicId,
    activeAulaScrollId,
    vqAulaScrollId,
    vqActiveBlockView?.blockId,
    vqActiveBlockView?.cycleStage,
    cursoTab,
    quickStudyTab,
  ]);

  useEffect(() => {
    const el = courseCatalogLogRef.current;
    if (!el) return;
    requestAnimationFrame(() => { el.scrollTop = 0; });
  }, [courseCatalogRun.logs.length]);

  useEffect(() => {
    if (!isAdmin && cursoTab === 'plano') setCursoTab('cronograma');
  }, [isAdmin, cursoTab]);

  useEffect(() => {
    if (!academiaExtraModal) return;
    setAcademiaExtraThinking(!!settingsRef.current.geminiThinkingEnabled);
    setAcademiaExtraAudit(!!settingsRef.current.auditQuestions);
  }, [academiaExtraModal?.topic?.id]); // eslint-disable-line

  useEffect(() => {
    if (!academiaRegenModal) return;
    setAcademiaRegenThinking(!!settingsRef.current.geminiThinkingEnabled);
    setAcademiaRegenAudit(!!settingsRef.current.auditQuestions);
  }, [academiaRegenModal?.topic?.id]); // eslint-disable-line

  useEffect(() => {
    reviewQueueRef.current = reviewQueue;
  }, [reviewQueue]);

  const captureReturnTarget = () => ({
    view,
    libFilter,
    activeFolderId,
    activeSubjectId,
    activeTopicId,
    activeSubjectVid,
    activeSubtopicVid,
    activeAula,
    videoSeek,
    vqSubject,
    vqTopic,
    vqAula,
    vqActiveBlock,
    vqActiveBlockView,
    cursoTab,
    quickStudyTab,
  });

  const restoreReturnTarget = (fallback = 'library') => {
    const target = viewReturnTarget;
    setViewReturnTarget(null);
    setReviewSession(null);
    if (!target) {
      setView(fallback);
      return;
    }
    setLibFilter(target.libFilter || 'gemini');
    setActiveFolderId(target.activeFolderId || null);
    setActiveSubjectId(target.activeSubjectId || null);
    setActiveTopicId(target.activeTopicId || null);
    setActiveSubjectVid(target.activeSubjectVid || null);
    setActiveSubtopicVid(target.activeSubtopicVid || null);
    setActiveAula(target.activeAula || null);
    setVideoSeek(target.videoSeek || null);
    setVqSubject(target.vqSubject || null);
    setVqTopic(target.vqTopic || null);
    setVqAula(target.vqAula || null);
    setVqActiveBlock(target.vqActiveBlock || null);
    setVqActiveBlockView(target.vqActiveBlockView || null);
    setCursoTab(target.cursoTab || 'videoaulas');
    setQuickStudyTab(target.quickStudyTab || 'lesson');
    setView(target.view || fallback);
  };

  const openViewWithReturn = (nextView, extra = {}) => {
    setViewReturnTarget({ ...captureReturnTarget(), ...extra });
    setView(nextView);
  };

  const openSettings = () => {
    openViewWithReturn('settings');
    setMenuOpen(false);
  };

  const openSpacedReview = (items = null) => {
    openViewWithReturn('spaced-review');
    if (items) setReviewSession({ items, index:0, sessionAnswers:{} });
  };

  // Load videoaulas: carrega UMA VEZ no login e usa localStorage como cache entre sessões
  const videoaulasLoadedRef = useRef(false);
  useEffect(() => {
    if (!user || user.isAnonymous || !canSeeVideoaulas || videoaulasLoadedRef.current) return;

    // Tentar cache do localStorage primeiro (evita loading na abertura)
    const cacheKey = `agora_videoaulas_${user.uid}`;
    const watchedKey = `agora_watched_${user.uid}`;
    try {
      const cached = localStorage.getItem(cacheKey);
      const cachedWatched = localStorage.getItem(watchedKey);
      if (cached) {
        setVideoaulasData(JSON.parse(cached));
        if (cachedWatched) setWatchedAulas(JSON.parse(cachedWatched));
        videoaulasLoadedRef.current = true;
        // Recarrega em background silenciosamente para atualizar cache
        refreshVideoaulasInBackground(user, cacheKey, watchedKey);
        return;
      }
    } catch(e) {}

    // Sem cache — carrega normalmente com loading
    videoaulasLoadedRef.current = true;
    setVideoaulasLoading(true);
    refreshVideoaulasInBackground(user, cacheKey, watchedKey, true);
  }, [user, canSeeVideoaulas]); // eslint-disable-line

  // Resetar ao fazer logout
  useEffect(() => {
    if (!user) { videoaulasLoadedRef.current = false; }
  }, [user]);

  const refreshVideoaulasInBackground = async (u, cacheKey, watchedKey, showLoading=false) => {
    try {
      const snap = await getDocs(collection(db, 'lessons'));
      if (!snap.empty) {
        const built = {};
        snap.forEach(d => {
          const data = d.data();
          const subj  = data.subject;
          const topic = data.topic;
          const isBonus = !!data.is_bonus;
          if (!subj || !topic) return;
          if (!built[subj]) built[subj] = {};
          if (!built[subj][topic]) built[subj][topic] = { 'Aulas Principais': [], 'Bônus': [] };
          const aula = {
            doc_id:            d.id,
            title:             data.title,
            embed_url:         data.embed_url,
            bunny_id:          data.bunny_id,
            duration_seconds:  data.duration_seconds  || 0,
            duration_formatted:data.duration_formatted || '',
            description:       data.description || data.ai_catalog?.description || '',
            ai_catalog:        data.ai_catalog || null,
          };
          if (isBonus) built[subj][topic]['Bônus'].push(aula);
          else         built[subj][topic]['Aulas Principais'].push(aula);
        });
        Object.values(built).forEach(topics =>
          Object.values(topics).forEach(cats =>
            Object.values(cats).forEach(arr =>
              arr.sort((a,b) => a.title.localeCompare(b.title, 'pt'))
            )
          )
        );
        setVideoaulasData(built);
        try { localStorage.setItem(cacheKey, JSON.stringify(built)); } catch(e) {}
      } else {
        setVideoaulasData({});
      }
      const ps = await getDoc(doc(db, 'users', u.uid, 'videoaulas_progress', 'watched'));
      if (ps.exists()) {
        const w = ps.data() || {};
        setWatchedAulas(w);
        try { localStorage.setItem(watchedKey, JSON.stringify(w)); } catch(e) {}
      }
    } catch(e) { console.error(e); if (showLoading) setVideoaulasData({}); }
    finally { if (showLoading) setVideoaulasLoading(false); }
  };

  useEffect(() => {
    if (!user || user.isAnonymous || !canSeeVideoaulas || !coursePlanLessonOrder.length || !videoaulasData) return;
    const hasDocIds = flattenCourseLessons(videoaulasData).some(lesson => lesson.aula?.doc_id);
    if (hasDocIds) return;
    refreshVideoaulasInBackground(user, `agora_videoaulas_${user.uid}`, `agora_watched_${user.uid}`, false);
  }, [user, canSeeVideoaulas, coursePlanLessonOrder.length, videoaulasData]); // eslint-disable-line

  const markAulaWatched = async (bunnyId, aula = null) => {
    if (!bunnyId) return;
    const already = !!watchedAulas[bunnyId];
    const u = { ...watchedAulas };
    if (already) { delete u[bunnyId]; } else { u[bunnyId] = true; recordLessonInterval(bunnyId, 0, aula?.duration_seconds || 0, true); }
    setWatchedAulas(u);
    addToast(already ? 'Aula desmarcada como assistida.' : 'Aula marcada como assistida.', already ? 'info' : 'success', 2500);
    // Atualizar cache local imediatamente
    if (user) try { localStorage.setItem(`agora_watched_${user.uid}`, JSON.stringify(u)); } catch(e) {}
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db,'users',user.uid,'videoaulas_progress','watched'), u);
    } catch(e) {
      addToast('Não consegui sincronizar agora, mas salvei no aparelho.', 'info', 3500);
    }
  };

  const resetWatchedProgress = async () => {
    setWatchedAulas({});
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db,'users',user.uid,'videoaulas_progress','watched'), {});
    } catch(e) {}
  };

  const persistDailyStats = (next, immediate=false) => {
    dailyStatsRef.current = next;
    setDailyStats(next);
    if (user) {
      try { localStorage.setItem(`agora_daily_stats_${user.uid}_${next.date}`, JSON.stringify(next)); } catch(e) {}
    }
    if (!user || user.isAnonymous) return;
    clearTimeout(dailyStatsSaveTimer.current);
    const save = () => setDoc(doc(db, 'users', user.uid, 'daily_stats', next.date), next, {merge:false}).catch(()=>{});
    if (immediate) save();
    else dailyStatsSaveTimer.current = setTimeout(save, 1200);
  };

  const ensureTodayStats = () => {
    const today = getTodayKey();
    const cur = dailyStatsRef.current || {};
    if (cur.date === today) return {
      date: today,
      questionKeys: cur.questionKeys || {},
      lessonIntervals: cur.lessonIntervals || {},
    };
    const fresh = {date:today, questionKeys:{}, lessonIntervals:{}};
    persistDailyStats(fresh, false);
    return fresh;
  };

  const trackQuestionAnswered = (key) => {
    if (!canUseAdvancedFeatures || !key) return;
    const cur = ensureTodayStats();
    if (cur.questionKeys?.[key]) return;
    persistDailyStats({...cur, questionKeys:{...(cur.questionKeys||{}), [key]:Date.now()}}, true);
  };

  const recordLessonInterval = (aulaId, fromSec, toSec, allowLong=false) => {
    if (!canUseAdvancedFeatures || !aulaId) return;
    const start = Math.max(0, Number(fromSec) || 0);
    const end = Math.max(0, Number(toSec) || 0);
    if (end - start < 1 || (!allowLong && end - start > 30)) return;
    const cur = ensureTodayStats();
    const before = cur.lessonIntervals?.[aulaId] || [];
    const merged = mergeIntervals([...before, [start, end]]);
    if (sumIntervalsSeconds(merged) === sumIntervalsSeconds(before)) return;
    persistDailyStats({...cur, lessonIntervals:{...(cur.lessonIntervals||{}), [aulaId]:merged}}, false);
  };

  useEffect(() => {
    const today = getTodayKey();
    const empty = {date:today, questionKeys:{}, lessonIntervals:{}};
    if (!user || user.isAnonymous) {
      dailyStatsRef.current = empty;
      setDailyStats(empty);
      return;
    }
    const cacheKey = `agora_daily_stats_${user.uid}_${today}`;
    try {
      const cached = JSON.parse(localStorage.getItem(cacheKey) || 'null');
      if (cached?.date === today) {
        dailyStatsRef.current = {...empty, ...cached, questionKeys:cached.questionKeys||{}, lessonIntervals:cached.lessonIntervals||{}};
        setDailyStats(dailyStatsRef.current);
      }
    } catch(e) {}
    (async () => {
      try {
        const snap = await getDoc(doc(db, 'users', user.uid, 'daily_stats', today));
        if (snap.exists()) {
          const data = snap.data() || {};
          const loaded = {...empty, ...data, questionKeys:data.questionKeys||{}, lessonIntervals:data.lessonIntervals||{}};
          dailyStatsRef.current = loaded;
          setDailyStats(loaded);
          try { localStorage.setItem(cacheKey, JSON.stringify(loaded)); } catch(e) {}
        }
      } catch(e) {}
    })();
  }, [user]);

  useEffect(() => {
    if (!canUseAdvancedFeatures || view !== 'videoaulas' || !activeAula) return;
    const aulaId = getAulaId(activeAula);
    if (!aulaId) return;
    videoWatchRef.current = { aulaId, last:null };
    const readSeconds = (raw) => {
      const data = typeof raw === 'string' ? (() => { try { return JSON.parse(raw); } catch(e) { return null; } })() : raw;
      if (!data) return null;
      const payload = data.data && typeof data.data === 'object' ? data.data : data;
      const seconds = payload.seconds ?? payload.currentTime ?? payload.time ?? payload.position ?? data.seconds ?? data.currentTime;
      const n = Number(seconds);
      return Number.isFinite(n) ? n : null;
    };
    const onMessage = (event) => {
      if (videoFrameRef.current?.contentWindow && event.source !== videoFrameRef.current.contentWindow) return;
      const seconds = readSeconds(event.data);
      if (seconds == null) return;
      const cur = videoWatchRef.current;
      if (cur.aulaId !== aulaId) return;
      if (cur.last != null && seconds > cur.last) recordLessonInterval(aulaId, cur.last, seconds);
      videoWatchRef.current = { aulaId, last:seconds };
    };
    window.addEventListener('message', onMessage);
    const subscribe = () => {
      const win = videoFrameRef.current?.contentWindow;
      if (!win) return;
      [
        {event:'command', func:'addEventListener', args:['timeupdate']},
        {context:'player.js', version:'0.0.11', event:'command', func:'addEventListener', args:['timeupdate']},
      ].forEach(msg => {
        try { win.postMessage(JSON.stringify(msg), '*'); } catch(e) {}
        try { win.postMessage(msg, '*'); } catch(e) {}
      });
    };
    const t1 = setTimeout(subscribe, 800);
    const t2 = setInterval(subscribe, 4000);
    return () => {
      clearTimeout(t1);
      clearInterval(t2);
      window.removeEventListener('message', onMessage);
    };
  }, [canUseAdvancedFeatures, view, activeAula?.bunny_id, activeAula?.embed_url]);

  const applyCoursePrefsPayload = (prefs = {}, { includeSchedule = true, includeSubjects = true } = {}) => {
    if (!prefs || typeof prefs !== 'object') return false;
    if (includeSubjects && Array.isArray(prefs.coursePlanSubjects)) setCoursePlanSubjects(prefs.coursePlanSubjects);
    if (Array.isArray(prefs.coursePlanLessonOrder)) setCoursePlanLessonOrder(prefs.coursePlanLessonOrder);
    if (typeof prefs.coursePlanLocked === 'boolean') setCoursePlanLocked(prefs.coursePlanLocked);
    if (prefs.courseOrgProposal && typeof prefs.courseOrgProposal === 'object') {
      setCourseOrgProposal(repairCourseOrgProposalWithManualOverrides(prefs.courseOrgProposal));
    }
    if (includeSchedule) {
      if (prefs.startDate) setCronStartDate(prefs.startDate);
      if (Number(prefs.courseScheduleWeeks) > 0) setCourseScheduleWeeks(Math.max(1, Math.min(104, Number(prefs.courseScheduleWeeks))));
      if (Number(prefs.courseScheduleSubjectBatchSize) > 0) setCourseScheduleSubjectBatchSize(Math.max(1, Math.min(COURSE_SCHEDULE_MAX_SUBJECT_BATCH_SIZE, Number(prefs.courseScheduleSubjectBatchSize))));
      if (prefs.courseSchedulePreset) setCourseSchedulePreset(String(prefs.courseSchedulePreset));
      if (prefs.courseScheduleMixPreset) setCourseScheduleMixPreset(String(prefs.courseScheduleMixPreset));
      if (prefs.courseCycleReviews && typeof prefs.courseCycleReviews === 'object') setCourseCycleReviews(prefs.courseCycleReviews);
    }
    return !!(prefs.courseOrgProposal && Array.isArray(prefs.coursePlanLessonOrder) && prefs.coursePlanLessonOrder.length);
  };

  const loadGlobalCourseOrganizationPrefs = async ({ includeSubjects = true } = {}) => {
    try {
      const snap = await getDoc(doc(db, 'config', 'curso_organization'));
      if (!snap.exists()) return false;
      return applyCoursePrefsPayload(snap.data() || {}, { includeSchedule:false, includeSubjects });
    } catch(e) {
      return false;
    }
  };

  // Load cronograma from Firestore — carrega UMA VEZ no login com cache localStorage
  const cronLoadedRef = useRef(false);
  useEffect(() => {
    if (!user || user.isAnonymous || !canSeeVideoaulas || cronLoadedRef.current) return;
    cronLoadedRef.current = true;

    const cacheKey = `agora_cronograma_${user.uid}`;
    try {
      const cached = localStorage.getItem(cacheKey);
      if (cached) {
        setCronograma(JSON.parse(cached));
        // Carregar prefs do usuário (data de início) em background
        getDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main')).then(async prefSnap => {
          const prefs = prefSnap.exists() ? (prefSnap.data() || {}) : {};
          const hasUserSubjects = Array.isArray(prefs.coursePlanSubjects) && prefs.coursePlanSubjects.length;
          applyCoursePrefsPayload(prefs);
          await loadGlobalCourseOrganizationPrefs({ includeSubjects:!hasUserSubjects });
        }).catch(()=>{ loadGlobalCourseOrganizationPrefs(); });
        return;
      }
    } catch(e) {}

    // Sem cache — carrega do Firestore
    setCronLoading(true);
    (async () => {
      try {
        const snap = await getDocs(collection(db, 'cronograma'));
        const weeks = [];
        snap.forEach(d => weeks.push(d.data()));
        weeks.sort((a,b) => a.week - b.week);
        setCronograma(weeks);
        try { localStorage.setItem(cacheKey, JSON.stringify(weeks)); } catch(e) {}
        const prefSnap = await getDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main'));
        let hasUserSubjects = false;
        if (prefSnap.exists()) {
          const prefs = prefSnap.data() || {};
          hasUserSubjects = Array.isArray(prefs.coursePlanSubjects) && prefs.coursePlanSubjects.length;
          applyCoursePrefsPayload(prefs);
        }
        await loadGlobalCourseOrganizationPrefs({ includeSubjects:!hasUserSubjects });
      } catch(e) { setCronograma([]); }
      finally { setCronLoading(false); }
    })();
  }, [user, canSeeVideoaulas]); // eslint-disable-line

  // Resetar ao logout
  useEffect(() => {
    if (!user || !canSeeVideoaulas) {
      if (user && !canSeeVideoaulas) {
        setVideoaulasData(null);
        setWatchedAulas({});
        videoaulasLoadedRef.current = false;
      }
      cronLoadedRef.current = false;
      setCronograma(null);
      setCoursePlanSubjects([]);
      setCoursePlanLessonOrder([]);
      setCoursePlanLocked(false);
      setCourseScheduleWeeks(COURSE_SCHEDULE_DEFAULT_WEEKS);
      setCourseScheduleSubjectBatchSize(COURSE_SCHEDULE_DEFAULT_SUBJECT_BATCH_SIZE);
      setCourseSchedulePreset(COURSE_SCHEDULE_DEFAULT_ORDER_PRESET);
      setCourseScheduleMixPreset(COURSE_SCHEDULE_DEFAULT_MIX_PRESET);
      setCourseScheduleSubjectsOpen(false);
      setCourseScheduleSettingsOpen(false);
      setCourseCycleReviews({});
      setCourseOrgProposal(null);
      setCourseOrgRun({ running:false, current:0, total:0, logs:[] });
      courseGlobalOrgPublishedRef.current = false;
    }
  }, [user, canSeeVideoaulas]);

  // Load reviewQueue — carrega uma vez no login
  useEffect(() => {
    if (!user || user.isAnonymous || reviewLoaded) return;
    setReviewLoaded(true);
    (async () => {
      try {
        const snap = await getDocs(collection(db, 'users', user.uid, 'vq_review'));
        const loaded = {};
        snap.forEach(d => { loaded[d.id] = d.data(); });
        reviewQueueRef.current = loaded;
        setReviewQueue(loaded);
      } catch(e) {}
    })();
  }, [user]); // eslint-disable-line

  useEffect(() => {
    if (!user) { setReviewLoaded(false); reviewQueueRef.current = {}; setReviewQueue({}); }
  }, [user]);

  const saveCronStartDate = async (dateStr) => {
    setCronStartDate(dateStr);
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main'), { startDate: dateStr }, { merge: true });
    } catch(e) {}
  };

  const saveCoursePlanPrefs = async (nextSubjects = coursePlanSubjects, nextLocked = coursePlanLocked, nextLessonOrder = coursePlanLessonOrder) => {
    const cleanSubjects = [...new Set((nextSubjects || []).filter(Boolean))];
    const cleanLessonOrder = [...new Set((nextLessonOrder || []).filter(Boolean).map(String))];
    setCoursePlanSubjects(cleanSubjects);
    setCoursePlanLessonOrder(cleanLessonOrder);
    setCoursePlanLocked(!!nextLocked);
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main'), {
        coursePlanSubjects:cleanSubjects,
        coursePlanLessonOrder:cleanLessonOrder,
        coursePlanLocked:!!nextLocked,
      }, { merge:true });
    } catch(e) {
      addToast('Não consegui sincronizar o plano agora, mas mantive na tela.', 'info', 3500);
    }
  };

  const saveCourseSchedulePrefs = async ({ weeks = courseScheduleWeeks, subjectBatchSize = courseScheduleSubjectBatchSize, preset = courseSchedulePreset, mixPreset = courseScheduleMixPreset, subjects = coursePlanSubjects } = {}) => {
    const cleanWeeks = Math.max(1, Math.min(104, Number(weeks) || COURSE_SCHEDULE_DEFAULT_WEEKS));
    const cleanSubjectBatchSize = Math.max(1, Math.min(COURSE_SCHEDULE_MAX_SUBJECT_BATCH_SIZE, Number(subjectBatchSize) || COURSE_SCHEDULE_DEFAULT_SUBJECT_BATCH_SIZE));
    const cleanPreset = String(preset || 'custom');
    const cleanMixPreset = String(mixPreset || COURSE_SCHEDULE_DEFAULT_MIX_PRESET);
    const cleanSubjects = [...new Set((subjects || []).filter(Boolean))];
    setCourseScheduleWeeks(cleanWeeks);
    setCourseScheduleSubjectBatchSize(cleanSubjectBatchSize);
    setCourseSchedulePreset(cleanPreset);
    setCourseScheduleMixPreset(cleanMixPreset);
    if (cleanSubjects.length) setCoursePlanSubjects(cleanSubjects);
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main'), {
        courseScheduleWeeks:cleanWeeks,
        courseScheduleSubjectBatchSize:cleanSubjectBatchSize,
        courseSchedulePreset:cleanPreset,
        courseScheduleMixPreset:cleanMixPreset,
        ...(cleanSubjects.length ? { coursePlanSubjects:cleanSubjects } : {}),
      }, { merge:true });
    } catch(e) {
      addToast('Não consegui sincronizar o cronograma agora, mas mantive na tela.', 'info', 3500);
    }
  };

  const getCourseOrgPlanParts = (proposal) => ({
    subjects:(proposal?.subjects || []).map(item => item.subject).filter(Boolean),
    lessonOrder:(proposal?.subjects || []).flatMap(subjectProposal =>
      (subjectProposal.modules || []).flatMap(module => (module.lessons || []).map(lesson => lesson.lessonId))
    ).filter(Boolean),
  });

  useEffect(() => {
    if (!isAdmin || !user || user.isAnonymous || courseGlobalOrgPublishedRef.current) return;
    const proposal = repairCourseOrgProposalWithManualOverrides(courseOrgProposal);
    const { subjects, lessonOrder } = getCourseOrgPlanParts(proposal);
    if (!proposal?.subjects?.length || !subjects.length || !lessonOrder.length) return;
    courseGlobalOrgPublishedRef.current = true;
    setCourseOrgProposal(proposal);
    setDoc(doc(db, 'config', 'curso_organization'), {
      courseOrgProposal:proposal,
      coursePlanSubjects:subjects,
      coursePlanLessonOrder:lessonOrder,
      coursePlanLocked:true,
      updatedAt:Date.now(),
      updatedBy:user?.email || null,
    }, { merge:true }).catch(() => {
      addToast('Não consegui publicar automaticamente a organização global.', 'info', 4500);
    });
  }, [isAdmin, user?.uid, courseOrgProposal, coursePlanLessonOrder.length]); // eslint-disable-line

  const applyCourseOrgProposalToPlan = async (proposalOverride = null, options = {}) => {
    const proposal = repairCourseOrgProposalWithManualOverrides(proposalOverride || courseOrgProposal);
    const subjects = (proposal?.subjects || []).map(item => item.subject).filter(Boolean);
    const { lessonOrder } = getCourseOrgPlanParts(proposal);
    if (!subjects.length || !lessonOrder.length) {
      addToast('Gere uma proposta antes de aplicar ao plano.', 'info', 3500);
      return;
    }
    setCourseOrgProposal(proposal);
    if (user && !user.isAnonymous) {
      await setDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main'), { courseOrgProposal:proposal }, { merge:true });
    }
    if (isAdmin) {
      try {
        await setDoc(doc(db, 'config', 'curso_organization'), {
          courseOrgProposal:proposal,
          coursePlanSubjects:subjects,
          coursePlanLessonOrder:lessonOrder,
          coursePlanLocked:true,
          updatedAt:Date.now(),
          updatedBy:user?.email || null,
        }, { merge:true });
      } catch(e) {
        addToast('Apliquei para você, mas não consegui publicar a organização global.', 'info', 4500);
      }
    }
    await saveCoursePlanPrefs(subjects, true, lessonOrder);
    setCursoTab('plano');
    setView('curso');
    const movedCount = proposal.manualCorrections?.length || 0;
    addToast(options.auto ? `Lista corrigida manualmente e aplicada (${movedCount} aula${movedCount!==1?'s':''} movida${movedCount!==1?'s':''}).` : 'Proposta corrigida e aplicada ao Meu Plano.', 'success', 4500);
  };

  useEffect(() => {
    if (!isAdmin || !user || user.isAnonymous || courseManualRepairAppliedRef.current || courseOrgRun.running) return;
    const current = normalizeCourseOrgProposal(courseOrgProposal);
    if (!current?.subjects?.length) return;
    const repaired = repairCourseOrgProposalWithManualOverrides(current);
    const needsRepair = current.sourceMode !== COURSE_ORG_SOURCE_MODE
      || courseOrgProposalHasManualRelocatedModules(current)
      || (repaired.manualCorrections?.length || 0) > 0
      || (repaired.moduleCorrections?.length || 0) > 0;
    if (!needsRepair) return;
    courseManualRepairAppliedRef.current = true;
    applyCourseOrgProposalToPlan(repaired, { auto:true }).catch(() => {
      addToast('Não consegui aplicar a correção manual automaticamente.', 'error', 5000);
    });
  }, [isAdmin, user?.uid, courseOrgProposal, courseOrgRun.running]); // eslint-disable-line

  const saveCourseCycleReview = async (lessonId, stage) => {
    if (!lessonId || !stage) return;
    const next = {
      ...(courseCycleReviews || {}),
      [lessonId]: {
        ...(courseCycleReviews?.[lessonId] || {}),
        [stage]: Date.now(),
      },
    };
    setCourseCycleReviews(next);
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db, 'users', user.uid, 'curso_prefs', 'main'), { courseCycleReviews:next }, { merge:true });
    } catch(e) {
      addToast('Não consegui sincronizar essa revisão agora, mas marquei na tela.', 'info', 3500);
    }
  };

  // Calcula semana atual baseada na data de início
  const getCurrentWeek = () => {
    if (!cronStartDate) return null;
    const start = new Date(cronStartDate);
    const now = new Date();
    const diffMs = now - start;
    if (diffMs < 0) return 1;
    return Math.min(46, Math.floor(diffMs / (7 * 24 * 60 * 60 * 1000)) + 1);
  };

  // ── Revisão Espaçada ───────────────────────────────────────────────────────
  const SR_INTERVALS = [3, 7, 14, 30, 90]; // dias
  const MS_DAY = 86400000;

  const saveReviewQueue = async (updated) => {
    const previous = reviewQueueRef.current || {};
    const compacted = {};
    Object.entries(updated || {}).forEach(([aulaId, blocks]) => {
      const nextBlocks = {};
      Object.entries(blocks || {}).forEach(([blockId, qMap]) => {
        if (qMap && Object.keys(qMap).length) nextBlocks[blockId] = qMap;
      });
      if (Object.keys(nextBlocks).length) compacted[aulaId] = nextBlocks;
    });
    const removedAulaIds = Object.keys(previous).filter(aulaId => !Object.prototype.hasOwnProperty.call(compacted, aulaId));
    const changedAulaEntries = Object.entries(compacted).filter(([aulaId, data]) =>
      JSON.stringify(previous[aulaId] || null) !== JSON.stringify(data)
    );
    reviewQueueRef.current = compacted;
    setReviewQueue(compacted);
    if (!user || user.isAnonymous) return;
    for (const [aulaId, data] of changedAulaEntries) {
      await setDoc(doc(db, 'users', user.uid, 'vq_review', aulaId), data).catch(console.error);
    }
    for (const aulaId of removedAulaIds) {
      await deleteDoc(doc(db, 'users', user.uid, 'vq_review', aulaId)).catch(console.error);
    }
  };

  const directQuestionIds = (topic = {}) => new Set((topic.questions || []).map(q => String(q.id)));
  const fixationQuestionIds = (topic = {}) => new Set(Object.values(topic.fixationQuestions || {}).flat().map(q => String(q.id)));
  const extraBatteryQuestions = (block) => Array.isArray(block?.questions) ? block.questions : (Array.isArray(block) ? block : []);
  const academiaExtraBlockId = (topicId, block, index) => `academia_extra_${topicId}_${block?.id || `legacy_${index}`}`;
  const allTopicQuestionIds = (topic = {}) => new Set([
    ...directQuestionIds(topic),
    ...fixationQuestionIds(topic),
    ...(topic.extraBattery || []).flatMap(block => extraBatteryQuestions(block).map(q => String(q.id))),
  ]);

  const pruneEmbeddedSpacedReview = (subject) => {
    if (!subject || isFolderItem(subject)) return subject;
    let changed = false;
    const topics = (subject.topics || []).map(topic => {
      const spacedReview = topic.spacedReview || {};
      if (!Object.keys(spacedReview).length) return topic;
      const validIds = allTopicQuestionIds(topic);
      const nextSpacedReview = Object.fromEntries(
        Object.entries(spacedReview).filter(([qId]) => validIds.has(String(qId)))
      );
      if (Object.keys(nextSpacedReview).length === Object.keys(spacedReview).length) return topic;
      changed = true;
      return { ...topic, spacedReview:nextSpacedReview };
    });
    return changed ? { ...subject, topics } : subject;
  };

  const pruneReviewBlockToQuestionIds = (queue, aulaId, blockId, validIds) => {
    const block = queue?.[aulaId]?.[blockId];
    if (!block) return { queue, changed:false };
    const nextBlock = Object.fromEntries(
      Object.entries(block).filter(([qId]) => validIds.has(String(qId)))
    );
    if (Object.keys(nextBlock).length === Object.keys(block).length) return { queue, changed:false };
    const nextAula = { ...(queue[aulaId] || {}) };
    if (Object.keys(nextBlock).length) nextAula[blockId] = nextBlock;
    else delete nextAula[blockId];
    return { queue:{ ...queue, [aulaId]:nextAula }, changed:true };
  };

  const removeReviewBlock = (queue, aulaId, blockId) => {
    if (!queue?.[aulaId]?.[blockId]) return { queue, changed:false };
    const nextAula = { ...(queue[aulaId] || {}) };
    delete nextAula[blockId];
    return { queue:{ ...queue, [aulaId]:nextAula }, changed:true };
  };

  const pruneLibraryReviewQueueToCurrentSources = (queue) => {
    const items = libraryRef.current?.length ? libraryRef.current : library;
    const libraryTargets = {};
    const validAcademiaOrigin = (origin) => {
      if (origin?.source !== 'academia') return true;
      const sourceSubject = items.find(item =>
        !isFolderItem(item) &&
        item.source === 'academia' &&
        String(item.id) === String(origin.subjectId)
      );
      return !!sourceSubject?.topics?.some(topic => String(topic.id) === String(origin.topicId));
    };
    const setTarget = (aulaId, blockId, ids) => {
      if (!libraryTargets[aulaId]) libraryTargets[aulaId] = {};
      libraryTargets[aulaId][blockId] = ids;
    };

    items.filter(item => item && !isFolderItem(item)).forEach(subject => {
      const aulaId = `lib_${subject.id}`;
      (subject.topics || []).forEach(topic => {
        if (!validAcademiaOrigin(topic.origin)) return;
        setTarget(aulaId, `topic_${topic.id}`, directQuestionIds(topic));
        if (subject.source === 'academia') {
          setTarget(aulaId, `academia_fix_${topic.id}`, fixationQuestionIds(topic));
          (topic.extraBattery || []).forEach((block, index) => {
            setTarget(
              aulaId,
              academiaExtraBlockId(topic.id, block, index),
              new Set(extraBatteryQuestions(block).map(q => String(q.id)))
            );
          });
        }
      });
    });

    let changed = false;
    const nextQueue = {};
    Object.entries(queue || {}).forEach(([aulaId, blocks]) => {
      if (!aulaId.startsWith('lib_')) {
        nextQueue[aulaId] = blocks;
        return;
      }
      const targets = libraryTargets[aulaId] || {};
      const nextBlocks = {};
      Object.entries(blocks || {}).forEach(([blockId, qMap]) => {
        const validIds = targets[blockId];
        if (!validIds) {
          changed = true;
          return;
        }
        const nextQMap = Object.fromEntries(
          Object.entries(qMap || {}).filter(([qId]) => validIds.has(String(qId)))
        );
        if (Object.keys(nextQMap).length !== Object.keys(qMap || {}).length) changed = true;
        if (Object.keys(nextQMap).length) nextBlocks[blockId] = nextQMap;
      });
      if (Object.keys(nextBlocks).length) nextQueue[aulaId] = nextBlocks;
      else if (Object.keys(blocks || {}).length) changed = true;
    });

    return { queue:nextQueue, changed };
  };

  const pruneReviewQueueForSubjectChanges = async (previousSubjects = [], nextSubjects = []) => {
    let queue = reviewQueueRef.current || {};
    let changed = false;
    const nextById = new Map(nextSubjects.filter(Boolean).map(s => [String(s.id), s]));
    const mark = (result) => {
      if (!result.changed) return;
      queue = result.queue;
      changed = true;
    };

    previousSubjects.filter(Boolean).forEach(previousSubject => {
      if (isFolderItem(previousSubject)) return;
      const aulaId = `lib_${previousSubject.id}`;
      const nextSubject = nextById.get(String(previousSubject.id));
      if (!nextSubject || isFolderItem(nextSubject)) {
        if (queue[aulaId]) {
          const { [aulaId]: _removed, ...rest } = queue;
          queue = rest;
          changed = true;
        }
        return;
      }

      const nextTopics = new Map((nextSubject.topics || []).map(t => [String(t.id), t]));
      (previousSubject.topics || []).forEach(previousTopic => {
        const nextTopic = nextTopics.get(String(previousTopic.id));
        if (!nextTopic) {
          mark(removeReviewBlock(queue, aulaId, `topic_${previousTopic.id}`));
          mark(removeReviewBlock(queue, aulaId, `academia_fix_${previousTopic.id}`));
          (previousTopic.extraBattery || []).forEach((block, index) => {
            mark(removeReviewBlock(queue, aulaId, academiaExtraBlockId(previousTopic.id, block, index)));
          });
          return;
        }

        mark(pruneReviewBlockToQuestionIds(queue, aulaId, `topic_${previousTopic.id}`, directQuestionIds(nextTopic)));
        mark(pruneReviewBlockToQuestionIds(queue, aulaId, `academia_fix_${previousTopic.id}`, fixationQuestionIds(nextTopic)));

        const nextExtraBlocks = new Map((nextTopic.extraBattery || []).map((block, index) => [block?.id || `legacy_${index}`, { block, index }]));
        (previousTopic.extraBattery || []).forEach((previousBlock, previousIndex) => {
          const key = previousBlock?.id || `legacy_${previousIndex}`;
          const blockId = academiaExtraBlockId(previousTopic.id, previousBlock, previousIndex);
          const nextEntry = nextExtraBlocks.get(key);
          if (!nextEntry) {
            mark(removeReviewBlock(queue, aulaId, blockId));
            return;
          }
          mark(pruneReviewBlockToQuestionIds(
            queue,
            aulaId,
            blockId,
            new Set(extraBatteryQuestions(nextEntry.block).map(q => String(q.id)))
          ));
        });
      });
    });

    const currentSources = pruneLibraryReviewQueueToCurrentSources(queue);
    if (currentSources.changed) {
      queue = currentSources.queue;
      changed = true;
    }
    if (changed) await saveReviewQueue(queue);
  };

  const pruneReviewQueueForVqBlockChange = async (aulaId, previousData, nextData) => {
    let queue = reviewQueueRef.current || {};
    let changed = false;
    const previousBlocks = previousData?.blocks || {};
    const nextBlocks = nextData?.blocks || {};
    Object.entries(previousBlocks).forEach(([blockId]) => {
      const nextBlock = nextBlocks[blockId];
      if (!nextBlock) {
        const result = removeReviewBlock(queue, aulaId, blockId);
        if (result.changed) {
          queue = result.queue;
          changed = true;
        }
        return;
      }
      const result = pruneReviewBlockToQuestionIds(
        queue,
        aulaId,
        blockId,
        new Set((nextBlock.questions || []).map(q => String(q.id)))
      );
      if (result.changed) {
        queue = result.queue;
        changed = true;
      }
    });
    if (changed) await saveReviewQueue(queue);
  };

  useEffect(() => {
    if (!user || !library.length || !Object.keys(reviewQueueRef.current || {}).length) return;
    const result = pruneLibraryReviewQueueToCurrentSources(reviewQueueRef.current || {});
    if (result.changed) saveReviewQueue(result.queue);
  }, [user?.uid, library.length, reviewLoaded, reviewQueue]); // eslint-disable-line

  // Adiciona questões selecionadas à fila de revisão
  const addToReview = async (aulaId, blockId, selectedQIds, questions, meta = {}) => {
    const now = Date.now();
    const queue = reviewQueueRef.current || {};
    const cur = queue[aulaId] || {};
    const curBlock = cur[blockId] || {};
    const updated = { ...cur, [blockId]: { ...curBlock } };
    selectedQIds.forEach(qId => {
      const q = questions.find(x => x.id === qId);
      if (!updated[blockId][qId]) {
        updated[blockId][qId] = {
          interval: 0,
          dueDate: now + SR_INTERVALS[0] * MS_DAY,
          reviewSeed: Math.floor(Math.random() * 999999),
          source: meta.source || 'curso',
          subjectId: meta.subjectId || null,
          topicId: meta.topicId || null,
          aulaTitle: meta.aulaTitle || meta.subjectTitle || null,
          blockTitle: meta.blockTitle || null,
          question: q ? { ...q } : null,
        };
      }
    });
    await saveReviewQueue({ ...queue, [aulaId]: updated });
  };

  const updateReviewMembership = async (aulaId, blockId, selectedQIds = [], removeQIds = [], questions = [], meta = {}) => {
    const now = Date.now();
    const queue = reviewQueueRef.current || {};
    const cur = queue[aulaId] || {};
    const curBlock = cur[blockId] || {};
    const nextBlock = { ...curBlock };
    removeQIds.forEach(qId => delete nextBlock[qId]);
    selectedQIds.forEach(qId => {
      const q = questions.find(x => x.id === qId);
      if (!nextBlock[qId]) {
        nextBlock[qId] = {
          interval: 0,
          dueDate: now + SR_INTERVALS[0] * MS_DAY,
          reviewSeed: Math.floor(Math.random() * 999999),
          source: meta.source || 'curso',
          subjectId: meta.subjectId || null,
          topicId: meta.topicId || null,
          aulaTitle: meta.aulaTitle || meta.subjectTitle || null,
          blockTitle: meta.blockTitle || null,
          question: q ? { ...q } : null,
        };
      }
    });
    await saveReviewQueue({ ...queue, [aulaId]: { ...cur, [blockId]: nextBlock } });
  };

  // Atualiza após responder uma questão na revisão (acerto avança, erro volta)
  const updateReviewItem = async (aulaId, blockId, qId, correct) => {
    const queue = reviewQueueRef.current || {};
    const cur = queue[aulaId] || {};
    const item = cur[blockId]?.[qId];
    if (!item) return;
    const newInterval = correct
      ? Math.min(item.interval + 1, SR_INTERVALS.length - 1)
      : 0;
    const newDue = Date.now() + SR_INTERVALS[newInterval] * MS_DAY;
    const updated = {
      ...cur,
      [blockId]: { ...cur[blockId], [qId]: { ...item, interval: newInterval, dueDate: newDue, reviewSeed: Math.floor(Math.random() * 999999) } }
    };
    await saveReviewQueue({ ...queue, [aulaId]: updated });
  };

  // Remove questão da fila de revisão
  const removeFromReview = async (aulaId, blockId, qId) => {
    const queue = reviewQueueRef.current || {};
    const cur = queue[aulaId] || {};
    const updBlock = { ...(cur[blockId] || {}) };
    delete updBlock[qId];
    const updated = { ...cur, [blockId]: updBlock };
    await saveReviewQueue({ ...queue, [aulaId]: updated });
  };

  const removeManyFromReview = async (aulaId, blockId, qIds = []) => {
    if (!qIds.length) return;
    const queue = reviewQueueRef.current || {};
    const cur = queue[aulaId] || {};
    const updBlock = { ...(cur[blockId] || {}) };
    qIds.forEach(qId => delete updBlock[qId]);
    const updated = { ...cur, [blockId]: updBlock };
    await saveReviewQueue({ ...queue, [aulaId]: updated });
  };

  // Retorna todas as questões com revisão vencida hoje
  const getDueReviews = () => {
    const now = Date.now();
    const due = [];
    const resolveFromLibrary = (item, qId) => {
      if (item?.question) return item.question;
      const subj = library.find(s => String(s.id) === String(item?.subjectId));
      const topic = subj?.topics?.find(t => String(t.id) === String(item?.topicId));
      if (!topic) return null;
      const questions = subj.source === 'academia'
        ? Object.values(topic.fixationQuestions || {}).flat().concat((topic.extraBattery || []).flatMap(b => b.questions || b))
        : (topic.questions || []);
      return questions.find(q => q.id === qId) || null;
    };
    Object.entries(reviewQueue).forEach(([aulaId, blocks]) => {
      const aulaData = vqBlocks[aulaId];
      if (aulaData && !canSeeVideoaulas) return;
      Object.entries(blocks).forEach(([blockId, qMap]) => {
        const block = aulaData?.blocks?.[blockId];
        const questions = Array.isArray(block?.questions) ? block.questions : [];
        Object.entries(qMap).forEach(([qId, item]) => {
          if (item.dueDate <= now) {
            const itemSource = item.source || (aulaData ? 'curso' : 'oraculo');
            if (itemSource === 'curso' && !canSeeVideoaulas) return;
            const q = questions.find(x => x.id === qId) || resolveFromLibrary(item, qId);
            if (q) due.push({
              aulaId,
              blockId,
              qId,
              item,
              question: q,
              aulaTitle: item.aulaTitle || aulaData?.meta?.aulaTitle,
              blockTitle: item.blockTitle || block?.title,
              source: itemSource,
              subjectId: item.subjectId,
              topicId: item.topicId,
            });
          }
        });
      });
    });
    return due.sort((a, b) => a.item.dueDate - b.item.dueDate);
  };

  const isReviewItemFavorite = (reviewItem) => {
    if (!reviewItem) return false;
    if ((reviewItem.source || reviewItem.item?.source) === 'curso' || vqBlocks[reviewItem.aulaId]) {
      const block = vqBlocks[reviewItem.aulaId]?.blocks?.[reviewItem.blockId];
      return (block?.favorites || []).includes(reviewItem.qId);
    }
    const subj = library.find(s => String(s.id) === String(reviewItem.subjectId || reviewItem.item?.subjectId));
    const topic = subj?.topics?.find(t => String(t.id) === String(reviewItem.topicId || reviewItem.item?.topicId));
    return (topic?.favorites || []).includes(reviewItem.qId);
  };

  const toggleReviewFavorite = async (reviewItem) => {
    if (!reviewItem) return;
    if ((reviewItem.source || reviewItem.item?.source) === 'curso' || vqBlocks[reviewItem.aulaId]) {
      const aulaData = vqBlocks[reviewItem.aulaId];
      const block = aulaData?.blocks?.[reviewItem.blockId];
      if (!aulaData || !block) return;
      await saveVqBlock(reviewItem.aulaId, {...aulaData, blocks:{...aulaData.blocks,[reviewItem.blockId]:{...block,favorites:toggleInList(block.favorites||[], reviewItem.qId)}}});
      return;
    }
    const subj = library.find(s => String(s.id) === String(reviewItem.subjectId || reviewItem.item?.subjectId));
    const topic = subj?.topics?.find(t => String(t.id) === String(reviewItem.topicId || reviewItem.item?.topicId));
    if (!subj || !topic) return;
    await updateSubject({...subj, topics:subj.topics.map(t=>t.id===topic.id?{...t,favorites:toggleInList(t.favorites||[], reviewItem.qId)}:t)});
  };

  const getReviewOrigin = (reviewItem) => {
    if (!reviewItem) return {};
    if ((reviewItem.source || reviewItem.item?.source) === 'curso' || vqBlocks[reviewItem.aulaId]) {
      const aulaData = vqBlocks[reviewItem.aulaId];
      const block = aulaData?.blocks?.[reviewItem.blockId];
      return { type:'curso', aulaData, block };
    }
    const subj = library.find(s => String(s.id) === String(reviewItem.subjectId || reviewItem.item?.subjectId));
    const topic = subj?.topics?.find(t => String(t.id) === String(reviewItem.topicId || reviewItem.item?.topicId));
    return { type:'library', subj, topic };
  };

  const isReviewItemInNotebook = (reviewItem) => {
    const origin = getReviewOrigin(reviewItem);
    if (origin.type === 'curso') return listHasId(origin.block?.errorNotebook || [], reviewItem.qId);
    return listHasId(origin.topic?.errorNotebook || [], reviewItem.qId);
  };

  const setReviewNotebook = async (reviewItem, mode = 'toggle') => {
    if (!canUseAdvancedFeatures || !reviewItem) return;
    const origin = getReviewOrigin(reviewItem);
    const nextList = (list) => mode === 'add' ? addToList(list || [], reviewItem.qId) : toggleInList(list || [], reviewItem.qId);
    if (origin.type === 'curso') {
      if (!origin.aulaData || !origin.block) return;
      await saveVqBlock(reviewItem.aulaId, {...origin.aulaData, blocks:{...origin.aulaData.blocks,[reviewItem.blockId]:{...origin.block,errorNotebook:nextList(origin.block.errorNotebook)}}});
      return;
    }
    if (!origin.subj || !origin.topic) return;
    await updateSubject({...origin.subj, topics:origin.subj.topics.map(t=>t.id===origin.topic.id?{...t,errorNotebook:nextList(t.errorNotebook)}:t)});
  };

  // Total de revisões pendentes (para badge)
  const dueCount = getDueReviews().length;
  // Load vqBlocks — carrega UMA VEZ quando o usuário loga, não a cada troca de view
  const vqBlocksLoadedRef = useRef(false);
  useEffect(() => {
    if (!user || user.isAnonymous || vqBlocksLoadedRef.current) return;
    vqBlocksLoadedRef.current = true;
    (async () => {
      setVqLoading(true);
      try {
        const snap = await getDocs(collection(db, 'users', user.uid, 'vq_blocks'));
        const loaded = {};
        snap.forEach(d => { loaded[d.id] = d.data(); });
        setVqBlocks(loaded);
      } catch(e) { console.error('vqBlocks load error:', e); }
      finally { setVqLoading(false); }
    })();
  }, [user]); // eslint-disable-line

  // Resetar o cache quando o usuário faz logout
  useEffect(() => {
    if (!user) { vqBlocksLoadedRef.current = false; setVqBlocks({}); }
  }, [user]);

  // Save a single aula's vqBlock data to Firestore
  const resetCourseProgress = async () => {
    if (!user || user.isAnonymous) return;
    try {
      // 1. Clear watched status
      await setDoc(doc(db,'users',user.uid,'videoaulas_progress','watched'), {});
      setWatchedAulas({});
      localStorage.removeItem(`agora_watched_${user.uid}`);

      // 2. Delete all vq_blocks docs
      const blocksSnap = await getDocs(collection(db,'users',user.uid,'vq_blocks'));
      await Promise.all(blocksSnap.docs.map(d => deleteDoc(d.ref)));
      setVqBlocks({});

      // 3. Delete all vq_review docs
      const reviewSnap = await getDocs(collection(db,'users',user.uid,'vq_review'));
      await Promise.all(reviewSnap.docs.map(d => deleteDoc(d.ref)));
      reviewQueueRef.current = {};
      setReviewQueue({});

      setResetCourseModal(false);
      setResetCourseInput('');
      addToast('Progresso do curso apagado com sucesso.', 'success', 5000);
    } catch(e) {
      console.error('Reset failed:', e);
      addToast('Erro ao apagar progresso. Tente novamente.', 'info', 4000);
    }
  };

  const saveVqBlock = async (aulaId, data) => {
    const previousData = vqBlocksRef.current?.[aulaId];
    const updated = { ...(vqBlocksRef.current || {}), [aulaId]: data };
    vqBlocksRef.current = updated;
    setVqBlocks(updated);
    if (user && !user.isAnonymous) try {
      await setDoc(doc(db, 'users', user.uid, 'vq_blocks', aulaId), data);
    } catch(e) {}
    await pruneReviewQueueForVqBlockChange(aulaId, previousData, data);
  };

  // Build stable Firestore document ID — tenta bunny_id primeiro, depois título sanitizado (legacy)
  const aulaDocId = (aula) => {
    if (!aula) return 'unknown';
    if (aula.bunny_id) return aula.bunny_id;
    return (aula.title || '').replace(/\//g, '-').replace(/[^a-zA-Z0-9\-_]/g, '').trim().substring(0, 100) || 'unknown';
  };

  // Dado um aula, retorna a chave que de fato existe em vqBlocks (bunny_id ou título legacy)
  // Sempre retorna UMA chave determinística — nunca null para aulas válidas
  const aulaVqKey = (aula) => {
    if (!aula) return null;
    // 1. bunny_id exato
    if (aula.bunny_id && vqBlocks[aula.bunny_id]) return aula.bunny_id;
    // 2. título sanitizado sem espaços
    const titleKey = (aula.title || '').replace(/\//g, '-').replace(/[^a-zA-Z0-9\-_]/g, '').trim().substring(0, 100);
    if (vqBlocks[titleKey]) return titleKey;
    // 3. título sanitizado com espaços (formato mais antigo)
    const titleKeyOld = (aula.title || '').replace(/\//g, '-').replace(/[^a-zA-Z0-9\-_ ]/g, '').trim().substring(0, 100);
    if (vqBlocks[titleKeyOld]) return titleKeyOld;
    // 4. fallback preferencial — bunny_id é o formato novo padrão de escrita
    return aula.bunny_id || titleKey || 'unknown';
  };

  // Verifica se uma aula tem dados em vqBlocks (independente do formato da chave)
  const aulaHasVqData = (aula) => {
    if (!aula) return false;
    if (aula.bunny_id && vqBlocks[aula.bunny_id]?.meta?.totalQuestions) return true;
    const titleKey = (aula.title || '').replace(/\//g, '-').replace(/[^a-zA-Z0-9\-_]/g, '').trim().substring(0, 100);
    if (vqBlocks[titleKey]?.meta?.totalQuestions) return true;
    const titleKeyOld = (aula.title || '').replace(/\//g, '-').replace(/[^a-zA-Z0-9\-_ ]/g, '').trim().substring(0, 100);
    if (vqBlocks[titleKeyOld]?.meta?.totalQuestions) return true;
    return false;
  };



